export function LogExplorer({ records }) {
  const [active, setActive] = React.useState(0);
  const [expanded, setExpanded] = React.useState(new Set());
  const v = useVirtualizer({ count: records.length, getScrollElement: () => parentRef.current, estimateSize: () => 36, overscan: 12 });
  function onKeyDown(e) { if (e.key === 'j') setActive(i => Math.min(i + 1, records.length - 1)); if (e.key === 'k') setActive(i => Math.max(i - 1, 0)); if (e.key === 'Enter') toggleExpanded(records[active].id); if (e.shiftKey && e.key === 'G') setActive(records.length - 1); }
  return <section role="grid" aria-label="Logs" onKeyDown={onKeyDown} ref={parentRef} tabIndex={0}>{v.getVirtualItems().map(row => <div role="row" tabIndex={row.index === active ? 0 : -1} aria-selected={row.index === active} aria-label={`${records[row.index].level} ${records[row.index].message}`} style={{ transform: `translateY(${row.start}px)` }}><LogRow record={records[row.index]} expanded={expanded.has(records[row.index].id)} /></div>)}</section>;
}

export interface Command<TContext = void> {
  id: string;
  label: string;
  shortcut?: ReadonlyArray<string>;
  preview?: (ctx: TContext) => React.ReactNode;
  execute: (ctx: TContext) => void | Promise<PaletteMode<unknown> | void>;
}
export interface PaletteMode<TContext> {
  id: string;
  breadcrumb: string;
  context: TContext;
  getCommands: (ctx: TContext, query: string) => ReadonlyArray<Command<TContext>>;
}

// fuzzy.ts — bounded ranking, no external dep
export function rank<T extends { label: string }>(items: ReadonlyArray<T>, query: string): T[] {
  if (!query) return items.slice(0, 12);
  const q = query.toLowerCase();
  const scored: Array<{ item: T; score: number }> = [];
  for (const item of items) {
    const label = item.label.toLowerCase();
    const idx = label.indexOf(q);
    if (idx === -1) {
      let qi = 0;
      for (let i = 0; i < label.length && qi < q.length; i++) if (label[i] === q[qi]) qi++;
      if (qi === q.length) scored.push({ item, score: 50 + label.length });
      continue;
    }
    scored.push({ item, score: idx === 0 ? 0 : idx + 10 });
  }
  scored.sort((a, b) => a.score - b.score);
  return scored.slice(0, 12).map((s) => s.item);
}

