// CommandPalette.tsx
import { useCallback, useEffect, useMemo, useRef, useState } from 'react';
import { rank } from './fuzzy';
import { FocusCtx } from './CommandFocusContext';
import type { Command, PaletteMode } from './types';

interface Props<TRoot> { rootMode: PaletteMode<TRoot>; open: boolean; onClose: () => void; }

export function CommandPalette<TRoot>({ rootMode, open, onClose }: Props<TRoot>) {
  const [stack, setStack] = useState<ReadonlyArray<PaletteMode<unknown>>>([rootMode as PaletteMode<unknown>]);
  const [query, setQuery] = useState('');
  const [focusIdx, setFocusIdx] = useState(0);
  const inputRef = useRef<HTMLInputElement | null>(null);
  const active = stack[stack.length - 1];

  useEffect(() => { if (open) inputRef.current?.focus(); }, [open]);
  useEffect(() => { setFocusIdx(0); }, [query, stack.length]);

  const visible = useMemo(() => {
    const cmds = active.getCommands(active.context, query);
    return rank(cmds as ReadonlyArray<Command<unknown> & { label: string }>, query);
  }, [active, query]);

  const popMode = useCallback(() => {
    setStack((s) => (s.length > 1 ? s.slice(0, -1) : s));
    setQuery('');
  }, []);

  const execute = useCallback(async (cmd: Command<unknown>) => {
    const next = await cmd.execute(active.context);
    if (next && typeof next === 'object' && 'getCommands' in next) {
      setStack((s) => [...s, next as PaletteMode<unknown>]);
      setQuery('');
    } else {
      onClose();
    }
  }, [active, onClose]);

  const onKey = useCallback((e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'ArrowDown') { e.preventDefault(); setFocusIdx((i) => Math.min(i + 1, visible.length - 1)); }
    else if (e.key === 'ArrowUp') { e.preventDefault(); setFocusIdx((i) => Math.max(i - 1, 0)); }
    else if (e.key === 'Enter') { e.preventDefault(); const c = visible[focusIdx]; if (c) void execute(c); }
    else if (e.key === 'Backspace' && query === '' && stack.length > 1) { e.preventDefault(); popMode(); }
    else if (e.key === 'Escape') { e.preventDefault(); onClose(); }
  }, [visible, focusIdx, execute, query, stack.length, popMode, onClose]);

  if (!open) return null;
  const focused = visible[focusIdx] ?? null;

  return (
    <FocusCtx.Provider value={{ focused }}>
      <div role="dialog" aria-label="Command palette" className="fixed inset-0 z-50 flex items-start justify-center pt-[15vh]" onClick={onClose}>
        <div onClick={(e) => e.stopPropagation()} className="w-[640px] rounded-xl bg-[oklch(0.99_0.002_250/0.96)] dark:bg-[oklch(0.18_0.005_250/0.96)] backdrop-blur-xl shadow-2xl ring-1 ring-black/5 overflow-hidden flex" style={{ animation: 'paletteIn 80ms linear' }}>
          <div className="flex-1 flex flex-col">
            {stack.length > 1 && (
              <div className="px-3 pt-2 text-[11px] text-[oklch(0.5_0.005_250)] flex gap-1">
                {stack.map((m, i) => (
                  <span key={m.id} className={i === stack.length - 1 ? 'text-[oklch(0.3_0.01_250)] dark:text-[oklch(0.85_0.01_250)]' : ''}>
                    {i > 0 && <span className="opacity-50 mr-1">/</span>}{m.breadcrumb}
                  </span>
                ))}
              </div>
            )}
            <input
              ref={inputRef}
              value={query}
              onChange={(e) => setQuery(e.target.value)}
              onKeyDown={onKey}
              placeholder={active.breadcrumb === 'Home' ? 'Type a command or search…' : `Search in ${active.breadcrumb}…`}
              aria-label="Command input"
              aria-controls="palette-results"
              aria-activedescendant={focused ? `cmd-${focused.id}` : undefined}
              className="w-full px-3 py-3 bg-transparent outline-none text-[15px] font-medium text-[oklch(0.2_0.01_250)] dark:text-[oklch(0.92_0.01_250)] placeholder:text-[oklch(0.55_0.005_250)]"
            />
            <ul id="palette-results" role="listbox" className="max-h-[320px] overflow-y-auto border-t border-black/5 dark:border-white/5" style={{ animation: 'modeIn 120ms cubic-bezier(0.22, 1, 0.36, 1)' }}>
              {visible.map((cmd, i) => (
                <li key={cmd.id} id={`cmd-${cmd.id}`} role="option" aria-selected={i === focusIdx}
                    onMouseEnter={() => setFocusIdx(i)} onClick={() => void execute(cmd)}
                    className={`flex items-center justify-between px-3 py-[8px] text-[13px] cursor-pointer ${i === focusIdx ? 'bg-[oklch(0.94_0.01_250)] dark:bg-[oklch(0.24_0.01_250)]' : ''}`}>
                  <span>{cmd.label}</span>
                  {cmd.shortcut && <span className="font-mono text-[11px] text-[oklch(0.55_0.005_250)]">{cmd.shortcut.join(' ')}</span>}
                </li>
              ))}
              {visible.length === 0 && <li className="px-3 py-4 text-[12px] text-[oklch(0.55_0.005_250)]">No matches. Press \u232B to go back.</li>}
            </ul>
          </div>
          {focused?.preview && (
            <div className="w-[280px] border-l border-black/5 dark:border-white/5 p-3 text-[12px]">
              {focused.preview(active.context)}
            </div>
          )}
        </div>
      </div>
      <style>{`@keyframes paletteIn { from { opacity: 0 } to { opacity: 1 } } @keyframes modeIn { from { transform: translateX(8px); opacity: 0 } to { transform: translateX(0); opacity: 1 } } @media (prefers-reduced-motion: reduce) { [style*='paletteIn'], [style*='modeIn'] { animation: none !important } }`}</style>
      </div>
    </FocusCtx.Provider>
  );
}

export interface PresenceUser { id: string; name: string; colorIndex: number; }
export interface CursorState { x: number; y: number; targetX: number; targetY: number; lastMoveAt: number; }

// useRafLerp.ts — drives non-React position updates
import { useEffect, useRef } from 'react';
export function useRafLerp(states: React.MutableRefObject<Map<string, CursorState>>, refs: React.MutableRefObject<Map<string, HTMLElement | null>>) {
  useEffect(() => {
    let raf = 0;
    const tick = () => {
      const now = performance.now();
      states.current.forEach((s, id) => {
        s.x += (s.targetX - s.x) * 0.4;
        s.y += (s.targetY - s.y) * 0.4;
        const el = refs.current.get(id);
        if (el) {
          const idleMs = now - s.lastMoveAt;
          const opacity = idleMs < 8000 ? 1 : idleMs > 30000 ? 0.3 : 1 - ((idleMs - 8000) / 2000) * 0.7;
          el.style.transform = `translate3d(${s.x}px, ${s.y}px, 0)`;
          el.style.opacity = String(Math.max(0.3, Math.min(1, opacity)));
        }
      });
      raf = requestAnimationFrame(tick);
    };
    raf = requestAnimationFrame(tick);
    return () => cancelAnimationFrame(raf);
  }, [refs, states]);
}

// occlusion.ts
export function detectClusters(positions: ReadonlyArray<{ id: string; x: number; y: number; tagWidth: number }>): Map<string, string[]> {
  const TAG_HEIGHT = 18;
  const clusters = new Map<string, string[]>();
  const claimed = new Set<string>();
  for (const a of positions) {
    if (claimed.has(a.id)) continue;
    const group = [a.id];
    for (const b of positions) {
      if (b.id === a.id || claimed.has(b.id)) continue;
      const overlapX = Math.abs(a.x - b.x) < (a.tagWidth + b.tagWidth) / 2;
      const overlapY = Math.abs(a.y - b.y) < TAG_HEIGHT + 4;
      if (overlapX && overlapY) { group.push(b.id); claimed.add(b.id); }
    }
    if (group.length > 1) clusters.set(a.id, group);
    claimed.add(a.id);
  }
  return clusters;
}

// PresenceLayer.tsx
import { memo, useEffect, useRef } from 'react';
import type { PresenceUser, CursorState } from './types';
import { useRafLerp } from './useRafLerp';
import { detectClusters } from './occlusion';

const PALETTE = ['oklch(0.65 0.18 25)','oklch(0.7 0.16 145)','oklch(0.6 0.2 280)','oklch(0.72 0.15 60)','oklch(0.62 0.19 200)','oklch(0.68 0.17 320)','oklch(0.66 0.16 100)','oklch(0.6 0.2 0)','oklch(0.7 0.14 240)','oklch(0.64 0.18 50)','oklch(0.66 0.17 170)','oklch(0.62 0.19 300)'] as const;

interface Props<U extends PresenceUser> { users: ReadonlyArray<U>; subscribe: (cb: (id: string, x: number, y: number) => void) => () => void; }

export function PresenceLayer<U extends PresenceUser>({ users, subscribe }: Props<U>) {
  const states = useRef<Map<string, CursorState>>(new Map());
  const refs = useRef<Map<string, HTMLElement | null>>(new Map());
  const clusterRef = useRef<Map<string, string[]>>(new Map());

  useEffect(() => {
    return subscribe((id, x, y) => {
      const existing = states.current.get(id);
      const now = performance.now();
      if (existing) { existing.targetX = x; existing.targetY = y; existing.lastMoveAt = now; }
      else states.current.set(id, { x, y, targetX: x, targetY: y, lastMoveAt: now });
    });
  }, [subscribe]);

  useRafLerp(states, refs);

  useEffect(() => {
    let raf = 0;
    const pass = () => {
      const positions: Array<{ id: string; x: number; y: number; tagWidth: number }> = [];
      states.current.forEach((s, id) => positions.push({ id, x: s.x, y: s.y, tagWidth: 60 }));
      clusterRef.current = detectClusters(positions);
      raf = requestAnimationFrame(pass);
    };
    raf = requestAnimationFrame(pass);
    return () => cancelAnimationFrame(raf);
  }, []);

  return (
    <div aria-hidden="true" className="pointer-events-none fixed inset-0 z-40 contain-layout-paint">
      {users.map((u) => (
        <Cursor key={u.id} user={u} setRef={(el) => refs.current.set(u.id, el)} clusterRef={clusterRef} />
      ))}
    </div>
  );
}

const Cursor = memo(function Cursor<U extends PresenceUser>({ user, setRef, clusterRef }: { user: U; setRef: (el: HTMLDivElement | null) => void; clusterRef: React.MutableRefObject<Map<string, string[]>> }) {
  const color = PALETTE[user.colorIndex % PALETTE.length];
  const isClustered = clusterRef.current.has(user.id) || Array.from(clusterRef.current.values()).some(g => g.includes(user.id) && g[0] !== user.id);
  return (
    <div ref={setRef} className="absolute top-0 left-0 will-change-transform" style={{ transition: 'opacity 80ms linear' }}>
      <svg width="16" height="18" viewBox="0 0 16 18"><path d="M0 0 L0 13 L4 10 L7 17 L9 16 L6 9 L11 9 Z" fill={color} stroke="white" strokeWidth="1" /></svg>
      {!isClustered && (
        <div className="absolute top-[18px] left-[12px] px-1.5 py-0.5 rounded text-[11px] font-medium leading-none" style={{ background: color, color: 'oklch(0.99 0.002 250)' }}>
          {user.name}
        </div>
      )}
    </div>
  );
});

export function resistanceCurve(x: number): number {
  if (x < 0) return x * 0.2;
  if (x <= 80) return x;
  if (x <= 160) return 80 + (x - 80) * 0.6;
  return 128 + (x - 160) * 0.3;
}

export type Zone = 'rest' | 'preview' | 'commit' | 'expanded';
export function zoneFor(displayedX: number): Zone {
  if (displayedX < 40) return 'rest';
  if (displayedX < 80) return 'preview';
  if (displayedX < 128) return 'commit';
  return 'expanded';
}

// SwipeRow.tsx
import { useCallback, useEffect, useRef, useState } from 'react';
import { resistanceCurve, zoneFor, type Zone } from './curve';

interface Actions { archive: () => void; snooze?: () => void; del?: () => void; }
interface Props<T> { item: T; children: React.ReactNode; actions: Actions; }

export function SwipeRow<T>({ item: _item, children, actions }: Props<T>) {
  const rowRef = useRef<HTMLDivElement | null>(null);
  const bgRef = useRef<HTMLDivElement | null>(null);
  const iconRef = useRef<HTMLDivElement | null>(null);
  const startX = useRef(0);
  const rawX = useRef(0);
  const committed = useRef(false);
  const hapticArmed = useRef(true);
  const [zone, setZone] = useState<Zone>('rest');
  const [archived, setArchived] = useState(false);

  const apply = useCallback((displayedX: number) => {
    const row = rowRef.current; const bg = bgRef.current; const ic = iconRef.current;
    if (!row || !bg || !ic) return;
    row.style.transform = `translateX(${displayedX}px)`;
    const z = zoneFor(displayedX);
    setZone(z);
    if (z === 'rest') { bg.style.background = 'transparent'; ic.style.opacity = '0.4'; }
    else if (z === 'preview') { bg.style.background = 'oklch(0.94 0.03 145 / 0.4)'; ic.style.opacity = '0.4'; }
    else if (z === 'commit') { bg.style.background = 'oklch(0.75 0.16 145)'; ic.style.opacity = '1'; }
    else { bg.style.background = 'oklch(0.7 0.18 30)'; ic.style.opacity = '1'; }
    if (z === 'commit' && hapticArmed.current) {
      hapticArmed.current = false;
      if ('vibrate' in navigator) navigator.vibrate(8);
    }
    if (z !== 'commit') hapticArmed.current = true;
  }, []);

  const onDown = useCallback((e: React.PointerEvent) => {
    if (committed.current) return;
    startX.current = e.clientX;
    rawX.current = 0;
    (e.target as Element).setPointerCapture(e.pointerId);
  }, []);

  const onMove = useCallback((e: React.PointerEvent) => {
    if (!startX.current) return;
    rawX.current = e.clientX - startX.current;
    apply(resistanceCurve(rawX.current));
  }, [apply]);

  const release = useCallback(() => {
    const displayed = resistanceCurve(rawX.current);
    startX.current = 0; rawX.current = 0;
    const row = rowRef.current; if (!row) return;
    if (displayed >= 80) {
      row.style.transition = 'transform 300ms cubic-bezier(0.16, 1, 0.3, 1)';
      row.style.transform = `translateX(${window.innerWidth}px)`;
      committed.current = true;
      window.setTimeout(() => {
        setArchived(true);
        actions.archive();
      }, 240);
    } else {
      const easing = displayed >= 40 ? 'cubic-bezier(0.34, 1.2, 0.64, 1)' : 'cubic-bezier(0.36, 0, 0.66, 1)';
      const dur = displayed >= 40 ? 300 : 200;
      row.style.transition = `transform ${dur}ms ${easing}`;
      row.style.transform = 'translateX(0)';
      window.setTimeout(() => apply(0), dur);
    }
  }, [actions, apply]);

  useEffect(() => {
    if (!archived) return;
    const t = window.setTimeout(() => {
      const row = rowRef.current;
      if (row) { row.style.transition = 'height 200ms cubic-bezier(0.4, 0, 1, 1)'; row.style.height = '0px'; }
    }, 1500);
    return () => window.clearTimeout(t);
  }, [archived]);

  if (archived) {
    return (
      <div role="status" aria-live="polite" className="h-2 px-3 flex items-center bg-[oklch(0.96_0.005_250)] text-[11px] text-[oklch(0.5_0.005_250)] overflow-hidden">
        Archived — \u2190 to undo
      </div>
    );
  }

  return (
    <div className="relative h-14 overflow-hidden touch-pan-y select-none">
      <div ref={bgRef} className="absolute inset-0" aria-hidden="true" />
      <div ref={iconRef} className="absolute top-1/2 right-6 -translate-y-1/2 opacity-40" aria-hidden="true">
        <svg width="20" height="20" viewBox="0 0 24 24" fill="white"><path d="M3 7v13h18V7M1 3h22v4H1z M9 11h6" /></svg>
      </div>
      <div ref={rowRef} onPointerDown={onDown} onPointerMove={onMove} onPointerUp={release} onPointerCancel={release} role="button" aria-label={`Swipe to archive. Currently in ${zone} zone.`} className="relative h-full bg-[oklch(0.99_0.002_250)] dark:bg-[oklch(0.18_0.005_250)] flex items-center px-3 will-change-transform">
        {children}
      </div>
    </div>
  );
}

export interface Cohort { id: string; label: string; size: number; retention: ReadonlyArray<number | null>; }
