// scale.ts
import { oklch } from 'culori';
export function cellBg(value: number | null): string {
  if (value == null) return 'oklch(0.97 0.005 250)';
  const l = 0.95 - value * 0.6;
  const c = 0.02 + value * 0.16;
  return `oklch(${l.toFixed(3)} ${c.toFixed(3)} 250)`;
}
export function cellTextColor(value: number | null): string {
  if (value == null) return 'oklch(0.55 0.005 250)';
  const l = 0.95 - value * 0.6;
  return l < 0.6 ? 'oklch(0.97 0.005 250)' : 'oklch(0.2 0.01 250)';
}

