import { createContext, useContext, useState } from 'react';
interface Hover { row: number; col: number; }
interface Ctx { hover: Hover | null; setHover: (h: Hover | null) => void; }
const C = createContext<Ctx | null>(null);
export function HeatmapHoverProvider({ children }: { children: React.ReactNode }) {
  const [hover, setHover] = useState<Hover | null>(null);
  return <C.Provider value={{ hover, setHover }}>{children}</C.Provider>;
}
export function useHeatmapHover(): Ctx { const v = useContext(C); if (!v) throw new Error('provider'); return v; }

// RetentionHeatmap.tsx
import { useState, useCallback } from 'react';
import type { Cohort, DrilldownUser } from './types';
import { cellBg, cellTextColor } from './scale';
import { HeatmapHoverProvider, useHeatmapHover } from './HeatmapHoverContext';

interface Props<TC extends Cohort> {
  cohorts: ReadonlyArray<TC>;
  weekLabels: ReadonlyArray<string>;
  getCellUsers: (cohortId: string, weekIndex: number) => Promise<ReadonlyArray<DrilldownUser>>;
}

export function RetentionHeatmap<TC extends Cohort>({ cohorts, weekLabels, getCellUsers }: Props<TC>) {
  return (
    <HeatmapHoverProvider>
      <HeatmapInner cohorts={cohorts} weekLabels={weekLabels} getCellUsers={getCellUsers} />
    </HeatmapHoverProvider>
  );
}

function HeatmapInner<TC extends Cohort>({ cohorts, weekLabels, getCellUsers }: Props<TC>) {
  const [drill, setDrill] = useState<{ cohortIdx: number; weekIdx: number } | null>(null);
  const [users, setUsers] = useState<ReadonlyArray<DrilldownUser>>([]);
  const { setHover } = useHeatmapHover();

  const onCellClick = useCallback(async (cohortIdx: number, weekIdx: number) => {
    if (drill && drill.cohortIdx === cohortIdx && drill.weekIdx === weekIdx) {
      setDrill(null); setUsers([]); return;
    }
    setDrill({ cohortIdx, weekIdx });
    const u = await getCellUsers(cohorts[cohortIdx].id, weekIdx);
    setUsers(u);
  }, [drill, cohorts, getCellUsers]);

  return (
    <div className="font-sans text-[oklch(0.2_0.01_250)]" role="grid" aria-label="Cohort retention heatmap">
      <div className="flex gap-[1px] pl-[120px] pr-[108px] mb-1">
        {weekLabels.map((w) => (
          <div key={w} className="w-10 text-center text-[11px] text-[oklch(0.55_0.005_250)]">{w}</div>
        ))}
      </div>
      {cohorts.map((cohort, ci) => (
        <div key={cohort.id}>
          <div role="row" className="flex items-center gap-[1px]" onMouseLeave={() => setHover(null)}>
            <div className="w-[120px] pr-2 text-right text-[11px] truncate">{cohort.label} <span className="text-[oklch(0.55_0.005_250)]">({cohort.size})</span></div>
            {cohort.retention.map((v, wi) => (
              <Cell key={wi} value={v} row={ci} col={wi} onClick={() => onCellClick(ci, wi)} />
            ))}
            <div className="w-24 ml-3"><Sparkline values={cohort.retention} /></div>
          </div>
          {drill?.cohortIdx === ci && (
            <div role="region" aria-label="Drill-down details" className="ml-[120px] mr-[108px] my-1 bg-[oklch(0.97_0.005_250)] rounded p-3 overflow-hidden" style={{ animation: 'drillIn 300ms cubic-bezier(0.22, 1, 0.36, 1)' }}>
              <div className="text-[11px] text-[oklch(0.55_0.005_250)] mb-2">{cohort.label} → Week {drill.weekIdx + 1} retained users</div>
              <ul className="grid grid-cols-2 gap-x-6 gap-y-1">
                {users.slice(0, 12).map((u) => (
                  <li key={u.id} className="flex justify-between text-[12px]">
                    <span>{u.name}</span><span className="text-[11px] text-[oklch(0.55_0.005_250)]">{new Date(u.joinedAt).toLocaleDateString()}</span>
                  </li>
                ))}
              </ul>
            </div>
          )}
        </div>
      ))}
      <style>{`@keyframes drillIn { from { max-height: 0; opacity: 0 } to { max-height: 240px; opacity: 1 } } @media (prefers-reduced-motion: reduce) { [style*='drillIn'] { animation: none !important } }`}</style>
    </div>
  );
}

function Cell({ value, row, col, onClick }: { value: number | null; row: number; col: number; onClick: () => void }) {
  const { hover, setHover } = useHeatmapHover();
  const isHover = hover?.row === row && hover?.col === col;
  const isGuideRow = hover?.row === row;
  const isGuideCol = hover?.col === col;
  return (
    <button
      type="button"
      role="gridcell"
      aria-label={value == null ? 'No data' : `${(value * 100).toFixed(1)}% retention`}
      onClick={onClick}
      onMouseEnter={() => setHover({ row, col })}
      className="w-10 h-8 text-[11px] tabular-nums font-medium relative"
      style={{ background: cellBg(value), color: cellTextColor(value), outline: isHover ? '1px solid oklch(0.2 0.01 250)' : (isGuideRow || isGuideCol ? '1px dashed oklch(0.4 0.005 250 / 0.5)' : 'none'), outlineOffset: '-1px' }}
    >
      {value == null ? '—' : `${Math.round(value * 100)}`}
    </button>
  );
}

function Sparkline({ values }: { values: ReadonlyArray<number | null> }) {
  const W = 96, H = 16;
  const pts = values.map((v, i) => v == null ? null : { x: (i / (values.length - 1)) * W, y: H - v * H }).filter((p): p is { x: number; y: number } => !!p);
  if (pts.length < 2) return null;
  const d = pts.map((p, i) => `${i ? 'L' : 'M'}${p.x.toFixed(1)} ${p.y.toFixed(1)}`).join(' ');
  return <svg width={W} height={H}><path d={d} stroke="oklch(0.55 0.03 250)" fill="none" strokeWidth="1" /></svg>;
}

export class BloomFilter {
  private bits: Uint8Array;
  private size: number;
  constructor(sizeBits = 8192, public hashCount = 3) {
    this.size = sizeBits;
    this.bits = new Uint8Array(sizeBits / 8);
  }
  static from(b64: string): BloomFilter {
    const bin = atob(b64);
    const arr = new Uint8Array(bin.length);
    for (let i = 0; i < bin.length; i++) arr[i] = bin.charCodeAt(i);
    const f = new BloomFilter(arr.length * 8);
    f.bits = arr;
    return f;
  }
  toBase64(): string { let s = ''; for (const b of this.bits) s += String.fromCharCode(b); return btoa(s); }
  private hashes(key: string): number[] {
    let h1 = 0, h2 = 0;
    for (let i = 0; i < key.length; i++) { const c = key.charCodeAt(i); h1 = (h1 * 31 + c) >>> 0; h2 = (h2 * 37 + c) >>> 0; }
    const out: number[] = [];
    for (let i = 0; i < this.hashCount; i++) out.push((h1 + i * h2) % this.size);
    return out;
  }
  add(key: string) { for (const i of this.hashes(key)) this.bits[i >> 3] |= 1 << (i & 7); }
  has(key: string): boolean { for (const i of this.hashes(key)) if (!(this.bits[i >> 3] & (1 << (i & 7)))) return false; return true; }
}

