// DeferredHint.tsx
import { useEffect, useRef, useState, type ReactNode } from 'react';
import { useHintMemory, persistHintMemory } from './HintMemoryContext';
import { useInteractionLog } from './InteractionLogContext';

interface Props {
  hintId: string;
  version: number;
  triggerAction: string;
  anchor: React.RefObject<HTMLElement | null>;
  children: ReactNode;
}

export function DeferredHint({ hintId, version, triggerAction, anchor, children }: Props) {
  const memory = useHintMemory();
  const log = useInteractionLog();
  const [show, setShow] = useState(false);
  const key = `${hintId}::v${version}`;
  const dismissed = useRef(memory.has(key));

  useEffect(() => {
    if (dismissed.current) return;
    const interval = window.setInterval(() => {
      if (log.countMouse(triggerAction) >= 2 && !dismissed.current) {
        setShow(true);
        memory.add(key);
        persistHintMemory(memory);
        dismissed.current = true;
        window.clearInterval(interval);
        window.setTimeout(() => setShow(false), 6000);
      }
    }, 500);
    return () => window.clearInterval(interval);
  }, [key, memory, log, triggerAction]);

  if (!show) return null;
  const rect = anchor.current?.getBoundingClientRect();
  if (!rect) return null;
  return (
    <div
      role="status"
      aria-live="polite"
      className="fixed z-30 px-3 py-2 rounded-md bg-[oklch(0.97_0.005_250)] dark:bg-[oklch(0.22_0.005_250)] border border-[oklch(0.85_0.005_250)] dark:border-[oklch(0.32_0.005_250)] text-[12px] text-[oklch(0.4_0.005_250)] dark:text-[oklch(0.75_0.005_250)] shadow-sm"
      style={{ top: rect.bottom + 8, left: rect.left, animation: 'hintIn 200ms cubic-bezier(0, 0, 0.2, 1)' }}
    >
      {children}
      <style>{`@keyframes hintIn { from { opacity: 0; transform: translateY(-4px) } to { opacity: 1; transform: translateY(0) } } @media (prefers-reduced-motion: reduce) { [style*='hintIn'] { animation: none !important } }`}</style>
    </div>
  );
}

