import { createContext, useContext, useReducer, type ReactNode } from 'react';
interface State { values: Record<string, unknown>; touched: Set<string>; errors: Map<string, string>; perFieldTimeMs: number[]; activeSteps: ReadonlyArray<string>; }
type Action = { type: 'set'; id: string; value: unknown } | { type: 'blur'; id: string; error: string | null; elapsedMs: number } | { type: 'serverError'; id: string; message: string } | { type: 'setActiveSteps'; ids: ReadonlyArray<string> };
function reducer(s: State, a: Action): State {
  switch (a.type) {
    case 'set': return { ...s, values: { ...s.values, [a.id]: a.value } };
    case 'blur': {
      const errors = new Map(s.errors);
      if (a.error) errors.set(a.id, a.error); else errors.delete(a.id);
      return { ...s, touched: new Set(s.touched).add(a.id), errors, perFieldTimeMs: [...s.perFieldTimeMs.slice(-19), a.elapsedMs] };
    }
    case 'serverError': { const errors = new Map(s.errors); errors.set(a.id, a.message); return { ...s, errors }; }
    case 'setActiveSteps': return { ...s, activeSteps: a.ids };
  }
}
const Ctx = createContext<{ state: State; dispatch: React.Dispatch<Action> } | null>(null);
export function FormStateProvider({ initialSteps, children }: { initialSteps: ReadonlyArray<string>; children: ReactNode }) {
  const [state, dispatch] = useReducer(reducer, { values: {}, touched: new Set(), errors: new Map(), perFieldTimeMs: [], activeSteps: initialSteps });
  return <Ctx.Provider value={{ state, dispatch }}>{children}</Ctx.Provider>;
}
export function useFormState() { const v = useContext(Ctx); if (!v) throw new Error('provider'); return v; }

// useTimeRemaining.ts
import { useMemo } from 'react';
import { useFormState } from './FormStateContext';
import type { StepDef } from './schema';
export function useTimeRemaining(allSteps: ReadonlyArray<StepDef>): string {
  const { state } = useFormState();
  return useMemo(() => {
    const median = state.perFieldTimeMs.length
      ? [...state.perFieldTimeMs].sort((a, b) => a - b)[Math.floor(state.perFieldTimeMs.length / 2)]
      : 14000;
    const remaining = allSteps.filter(s => state.activeSteps.includes(s.id))
      .flatMap(s => s.fields).filter(f => f.required && !(f.id in state.values)).length;
    const totalMs = remaining * median;
    if (totalMs < 60000) return `About ${Math.ceil(totalMs / 10000) * 10} seconds left`;
    return `About ${Math.ceil(totalMs / 60000)} minute${Math.ceil(totalMs / 60000) === 1 ? '' : 's'} left`;
  }, [state, allSteps]);
}

