import { useRef, useState, useCallback } from 'react';
import { useFormState } from './FormStateContext';
import type { FieldDef } from './schema';

export function Field<T>({ def }: { def: FieldDef<T> }) {
  const { state, dispatch } = useFormState();
  const value = (state.values[def.id] as T) ?? ('' as unknown as T);
  const error = state.errors.get(def.id);
  const focusedAt = useRef<number>(0);
  const [active, setActive] = useState(false);
  const showError = state.touched.has(def.id) && !!error;
  const showValid = state.touched.has(def.id) && !error && value !== '';

  const onBlur = useCallback(() => {
    setActive(false);
    const err = def.validate(value);
    const elapsed = performance.now() - focusedAt.current;
    dispatch({ type: 'blur', id: def.id, error: err, elapsedMs: elapsed });
  }, [def, value, dispatch]);

  return (
    <div className="mb-4">
      <label htmlFor={def.id} className="block text-[13px] font-medium text-[oklch(0.3_0.01_250)] mb-1.5">{def.label}</label>
      <div className="relative">
        <input
          id={def.id}
          value={String(value)}
          onChange={(e) => dispatch({ type: 'set', id: def.id, value: e.target.value as unknown as T })}
          onFocus={() => { focusedAt.current = performance.now(); setActive(true); }}
          onBlur={onBlur}
          aria-invalid={showError}
          aria-describedby={showError ? `${def.id}-err` : undefined}
          className={`w-full h-9 px-3 pr-8 text-[14px] rounded-md bg-white outline-none transition-[border-color] duration-150 border ${showError ? 'border-[oklch(0.6_0.18_25)]' : showValid ? 'border-[oklch(0.6_0.14_145)]' : active ? 'border-[oklch(0.5_0.005_250)]' : 'border-[oklch(0.85_0.005_250)]'}`}
        />
        {showValid && <svg aria-hidden="true" className="absolute right-2.5 top-2.5 transition-opacity duration-150" width="14" height="14" viewBox="0 0 14 14"><path d="M3 7l3 3 5-6" stroke="oklch(0.55 0.14 145)" strokeWidth="1.75" fill="none" strokeLinecap="round" /></svg>}
      </div>
      {showError && (
        <div id={`${def.id}-err`} role="alert" className="mt-1.5 text-[12px] text-[oklch(0.5_0.16_25)] flex items-center gap-2">
          {error}
          {def.serverFixable && (() => { const fixed = def.serverFixable(value); return fixed != null && fixed !== value ? (
            <button type="button" onClick={() => dispatch({ type: 'set', id: def.id, value: fixed })} className="underline underline-offset-2 hover:no-underline">Fix automatically</button>
          ) : null; })()}
        </div>
      )}
    </div>
  );
}

import { useFrame, useThree } from '@react-three/fiber';
import { Vector3, CatmullRomCurve3 } from 'three';
import { useMemo, useRef } from 'react';
import { useScrollContext } from './ScrollContext';

interface Props { anchors: ReadonlyArray<[number, number, number]>; manualControl: React.MutableRefObject<boolean>; }

export function CameraRig({ anchors, manualControl }: Props) {
  const { camera } = useThree();
  const { progressRef } = useScrollContext();
  const curve = useMemo(() => new CatmullRomCurve3(anchors.map(a => new Vector3(...a)), false, 'centripetal'), [anchors]);
  const target = useRef(new Vector3());
  useFrame(() => {
    if (manualControl.current) return;
    const t = Math.max(0, Math.min(1, progressRef.current));
    curve.getPoint(t, target.current);
    camera.position.lerp(target.current, 0.08);
    camera.lookAt(0, 0.4, 0);
  });
  return null;
}

// MaterialTransition.tsx — directional wipe shader
import { useFrame } from '@react-three/fiber';
import { useMemo, useRef } from 'react';
import { ShaderMaterial, Texture, Vector3 } from 'three';

export function useTransitioningMaterial(currentMap: Texture, pendingMap: Texture | null) {
  const matRef = useRef<ShaderMaterial>(new ShaderMaterial({
    uniforms: {
      uCurrent: { value: currentMap },
      uPending: { value: pendingMap },
      uProgress: { value: 0 },
      uDirection: { value: new Vector3(1, 0, 0) },
    },
    vertexShader: `varying vec2 vUv; void main() { vUv = uv; gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0); }`,
    fragmentShader: `
      varying vec2 vUv;
      uniform sampler2D uCurrent;
      uniform sampler2D uPending;
      uniform float uProgress;
      uniform vec3 uDirection;
      void main() {
        float edge = dot(vec2(uDirection.x, uDirection.y), vUv) - uProgress * 1.4 + 0.2;
        float band = smoothstep(0.0, 0.08, -edge);
        vec3 a = texture2D(uCurrent, vUv).rgb;
        vec3 b = texture2D(uPending, vUv).rgb;
        gl_FragColor = vec4(mix(a, b, band), 1.0);
      }`,
  }));
  const start = useRef<number | null>(null);
  useFrame((state) => {
    if (!pendingMap) return;
    if (start.current == null) start.current = state.clock.elapsedTime;
    const t = (state.clock.elapsedTime - start.current) / 0.4;
    matRef.current.uniforms.uProgress.value = Math.min(1, t);
    if (t >= 1) {
      matRef.current.uniforms.uCurrent.value = pendingMap;
      matRef.current.uniforms.uProgress.value = 0;
      start.current = null;
    }
    state.invalidate();
  });
  return matRef.current;
}

