import { useEffect, useState } from 'react';
export type Modality = 'touch' | 'mouse';
export function useInputModality(): Modality {
  const [modality, setModality] = useState<Modality>(() => (typeof window !== 'undefined' && matchMedia('(hover: none)').matches ? 'touch' : 'mouse'));
  useEffect(() => {
    const onPointer = (e: PointerEvent) => {
      setModality(e.pointerType === 'touch' || e.pointerType === 'pen' ? 'touch' : 'mouse');
    };
    window.addEventListener('pointerdown', onPointer);
    return () => window.removeEventListener('pointerdown', onPointer);
  }, []);
  return modality;
}

