import type { ReactNode } from 'react';
export interface InteractionAdapter<TItem> {
  rowProps: (item: TItem, isSelected: boolean) => Record<string, unknown>;
  renderAffordances: (item: TItem, isHover: boolean) => ReactNode;
  rowHeight: number;
}

export function makeDesktopAdapter<TItem extends { id: string }>(onAction: (id: string, a: string) => void): InteractionAdapter<TItem> {
  return {
    rowHeight: 32,
    rowProps: (item, isSelected) => ({
      tabIndex: isSelected ? 0 : -1,
      onKeyDown: (e: React.KeyboardEvent) => {
        if (e.key === 'Enter') onAction(item.id, 'open');
        if (e.key === 'e') onAction(item.id, 'archive');
      },
    }),
    renderAffordances: (item, isHover) => isHover ? <DesktopActions itemId={item.id} onAction={onAction} /> : null,
  };
}

export function makeTouchAdapter<TItem extends { id: string }>(onAction: (id: string, a: string) => void): InteractionAdapter<TItem> {
  return {
    rowHeight: 64,
    rowProps: (item) => ({
      onPointerDown: (e: React.PointerEvent) => { /* swipe tracking — see SwipeBinding */ },
    }),
    renderAffordances: () => null,
  };
}

function DesktopActions({ itemId, onAction }: { itemId: string; onAction: (id: string, a: string) => void }) {
  return (
