import { useEffect, useState } from 'react';
export function useMotionPreference(): 'full' | 'reduced' {
  const [pref, setPref] = useState<'full' | 'reduced'>(() => typeof window !== 'undefined' && matchMedia('(prefers-reduced-motion: reduce)').matches ? 'reduced' : 'full');
  useEffect(() => {
    const mq = matchMedia('(prefers-reduced-motion: reduce)');
    const onChange = () => setPref(mq.matches ? 'reduced' : 'full');
    mq.addEventListener('change', onChange);
    return () => mq.removeEventListener('change', onChange);
  }, []);
  return pref;
}

// useNarration.ts
import { useEffect, useRef, useState } from 'react';
export function useNarration(debounceMs = 600) {
  const [message, setMessage] = useState('');
  const timer = useRef<number | null>(null);
  const narrate = (msg: string) => {
    if (timer.current) window.clearTimeout(timer.current);
    timer.current = window.setTimeout(() => setMessage(msg), debounceMs);
  };
  useEffect(() => () => { if (timer.current) window.clearTimeout(timer.current); }, []);
  return { message, narrate };
}

