import { useCallback, useMemo, useRef, useState } from 'react';
import { useMotionPreference } from './useMotionPreference';
import { useNarration } from './useNarration';

export interface Column<TRow> { key: keyof TRow & string; header: string; sortable?: boolean; format?: (val: TRow[keyof TRow]) => string; }
interface Props<TRow extends { id: string }> { columns: ReadonlyArray<Column<TRow>>; rows: ReadonlyArray<TRow>; filter?: string; onDelete?: (id: string) => void; }

export function DataTable<TRow extends { id: string }>({ columns, rows, filter = '', onDelete }: Props<TRow>) {
