  const [sortDir, setSortDir] = useState<'asc' | 'desc'>('asc');
  const [focusedCell, setFocusedCell] = useState<{ row: number; col: number }>({ row: 0, col: 0 });
  const tableRef = useRef<HTMLTableElement | null>(null);

  const visible = useMemo(() => {
    let v = rows.slice();
    if (filter) v = v.filter(r => Object.values(r).some(val => String(val).toLowerCase().includes(filter.toLowerCase())));
    if (sortKey) v.sort((a, b) => {
      const av = String(a[sortKey as keyof TRow] ?? '');
      const bv = String(b[sortKey as keyof TRow] ?? '');
      return sortDir === 'asc' ? av.localeCompare(bv) : bv.localeCompare(av);
    });
    return v;
  }, [rows, filter, sortKey, sortDir]);

  // Narrate filter result changes
  useMemo(() => {
    if (filter) narrate(`Filtered to ${visible.length} of ${rows.length} ${rows.length === 1 ? 'row' : 'rows'}.`);
  }, [filter, visible.length, rows.length, narrate]);

  const onKey = useCallback((e: React.KeyboardEvent<HTMLTableElement>) => {
    const { row, col } = focusedCell;
    let next = { row, col };
    if (e.key === 'ArrowDown') next.row = Math.min(visible.length - 1, row + 1);
    else if (e.key === 'ArrowUp') next.row = Math.max(0, row - 1);
    else if (e.key === 'ArrowRight') next.col = Math.min(columns.length - 1, col + 1);
    else if (e.key === 'ArrowLeft') next.col = Math.max(0, col - 1);
    else if (e.key === 'Home') next.col = 0;
    else if (e.key === 'End') next.col = columns.length - 1;
    else if (e.key === 'Delete' && onDelete) { onDelete(visible[row].id); narrate('Row deleted.'); return; }
    else return;
    e.preventDefault();
    setFocusedCell(next);
    const cell = tableRef.current?.querySelector(`tbody tr:nth-child(${next.row + 1}) td:nth-child(${next.col + 1})`) as HTMLElement | null;
    cell?.focus();
  }, [focusedCell, visible, columns.length, onDelete, narrate]);

  return (
    <>
      <div role="status" aria-live="polite" aria-atomic="true" className="sr-only">{message}</div>
      <table ref={tableRef} onKeyDown={onKey} className="w-full border-collapse text-[13px]" role="grid" aria-rowcount={visible.length}>
        <thead>
          <tr>
            {columns.map((c) => (
              <th key={c.key} scope="col" aria-sort={sortKey === c.key ? (sortDir === 'asc' ? 'ascending' : 'descending') : 'none'} className="text-left text-[11px] uppercase tracking-wider font-semibold px-3 py-2 text-[oklch(0.55_0.005_250)] border-b border-[oklch(0.92_0.005_250)]">
                {c.sortable ? (
                  <button type="button" onClick={() => { if (sortKey === c.key) setSortDir(d => d === 'asc' ? 'desc' : 'asc'); else { setSortKey(c.key); setSortDir('asc'); } narrate(`Sorted by ${c.header}.`); }} className="flex items-center gap-1 hover:text-[oklch(0.3_0.005_250)] focus-visible:outline focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-[oklch(0.55_0.18_250)]">
                    {c.header}
                    <span aria-hidden="true" className="text-[10px]">{sortKey === c.key ? (sortDir === 'asc' ? '\u2191' : '\u2193') : ''}</span>
                  </button>
                ) : c.header}
              </th>
            ))}
          </tr>
        </thead>
        <tbody>
          {visible.map((row, ri) => (
            <tr key={row.id} className={motion === 'reduced' ? 'animate-[hcPulse_600ms_ease-out]' : 'transition-[background-color] duration-200'}>
              {columns.map((c, ci) => {
                const v = row[c.key];
                const display = c.format ? c.format(v) : String(v);
                return (
                  <td key={c.key} tabIndex={ri === focusedCell.row && ci === focusedCell.col ? 0 : -1} className="px-3 py-2 border-b border-[oklch(0.95_0.005_250)] focus-visible:outline focus-visible:outline-2 focus-visible:outline-offset-[-2px] focus-visible:outline-[oklch(0.55_0.18_250)]" aria-rowindex={ri + 1}>
                    {display}
                  </td>
                );
              })}
            </tr>
          ))}
        </tbody>
      </table>
      <style>{`@keyframes hcPulse { 0% { background: oklch(0.95 0.04 250) } 100% { background: transparent } } @media (forced-colors: active) { .focus-visible\\:outline:focus-visible { outline: 2px solid CanvasText !important } }`}</style>
    </>
  );
}

