// useThreadDraft.ts
import { useCallback, useEffect, useRef, useState } from 'react';
export function useThreadDraft(threadId: string) {
  const key = `draft:${threadId}`;
  const [text, setText] = useState<string>(() => (typeof localStorage !== 'undefined' ? localStorage.getItem(key) ?? '' : ''));
  const [restoredAt] = useState<number | null>(() => {
    if (typeof localStorage === 'undefined') return null;
    const meta = localStorage.getItem(`${key}:ts`);
    return meta ? Number(meta) : null;
  });
  const timer = useRef<number | null>(null);
  const update = useCallback((next: string) => {
    setText(next);
    if (timer.current) window.clearTimeout(timer.current);
    timer.current = window.setTimeout(() => {
      try { localStorage.setItem(key, next); localStorage.setItem(`${key}:ts`, String(Date.now())); } catch {}
    }, 400);
  }, [key]);
  const clear = useCallback(() => { setText(''); try { localStorage.removeItem(key); localStorage.removeItem(`${key}:ts`); } catch {} }, [key]);
  useEffect(() => () => { if (timer.current) window.clearTimeout(timer.current); }, []);
  return { text, update, clear, restoredAt };
}

// useOptimisticSubmit.ts
import { useCallback, useState } from 'react';
import type { BaseComment } from './types';

interface PostFn<C> { (body: string): Promise<C>; }

export function useOptimisticSubmit<C extends BaseComment>(initial: ReadonlyArray<C>, post: PostFn<C>) {
  const [comments, setComments] = useState<ReadonlyArray<C>>(initial);
  const submit = useCallback(async (body: string, currentUser: C['author']) => {
    const tempId = `temp-${crypto.randomUUID()}`;
    const pending = { id: tempId, author: currentUser, body, createdAt: Date.now(), status: 'pending' as const } as C;
    setComments((cs) => [...cs, pending]);
    try {
      const confirmed = await post(body);
      setComments((cs) => cs.map(c => c.id === tempId ? { ...confirmed, status: 'confirmed' as const } : c));
    } catch {
      // single silent retry
      try {
        const confirmed = await post(body);
        setComments((cs) => cs.map(c => c.id === tempId ? { ...confirmed, status: 'confirmed' as const } : c));
      } catch {
        setComments((cs) => cs.map(c => c.id === tempId ? { ...c, status: 'failed' as const } : c));
      }
    }
  }, [post]);
  const retry = useCallback(async (failedId: string) => {
    const failed = comments.find(c => c.id === failedId);
    if (!failed) return;
    setComments((cs) => cs.map(c => c.id === failedId ? { ...c, status: 'pending' as const } : c));
    try {
      const confirmed = await post(failed.body);
      setComments((cs) => cs.map(c => c.id === failedId ? { ...confirmed, status: 'confirmed' as const } : c));
    } catch {
      setComments((cs) => cs.map(c => c.id === failedId ? { ...c, status: 'failed' as const } : c));
    }
  }, [comments, post]);
  const discard = useCallback((id: string) => setComments(cs => cs.filter(c => c.id !== id)), []);
  return { comments, submit, retry, discard };
}

