      {isFailed && (
        <div role="alert" className="mt-2 flex items-center gap-3 text-[12px] text-[oklch(0.55_0.005_250)]">
          <span>Couldn't send</span>
          <button type="button" onClick={onRetry} className="underline underline-offset-2 hover:no-underline">Retry</button>
