import { memo, useEffect, useRef } from 'react';
import { PriceCell } from './PriceCell';

export interface BookLevel { price: number; size: number; total: number; }

interface Props { level: BookLevel; side: 'bid' | 'ask'; maxTotal: number; decimals: number; sizeDecimals: number; onPriceClick: (price: number, size?: number) => void; updateTick: number; }

export const BookRow = memo(function BookRow({ level, side, maxTotal, decimals, sizeDecimals, onPriceClick, updateTick }: Props) {
  const rowRef = useRef<HTMLDivElement | null>(null);
  const tickRef = useRef(updateTick);
  useEffect(() => {
    if (tickRef.current === updateTick) return;
    tickRef.current = updateTick;
    const el = rowRef.current;
    if (!el) return;
    el.style.boxShadow = `inset 2px 0 0 0 var(--${side}-text)`;
    const id = window.setTimeout(() => { if (el) el.style.boxShadow = 'none'; }, 16);
    return () => window.clearTimeout(id);
  }, [updateTick, side]);
  const depthFraction = Math.min(1, level.total / maxTotal);
  const bgGradient = side === 'bid'
    ? `linear-gradient(to left, var(--bid-depth) ${depthFraction * 100}%, transparent ${depthFraction * 100}%)`
    : `linear-gradient(to right, var(--ask-depth) ${depthFraction * 100}%, transparent ${depthFraction * 100}%)`;
  return (
    <div
      ref={rowRef}
      role="button"
      tabIndex={0}
      onClick={(e) => onPriceClick(level.price, e.shiftKey ? level.size : undefined)}
      onKeyDown={(e) => { if (e.key === 'Enter') onPriceClick(level.price); }}
      aria-label={`${side} ${level.size} at ${level.price}`}
      className="flex items-center justify-between h-4 px-2 cursor-pointer hover:bg-[oklch(0.18_0.005_250)]"
      style={{ background: bgGradient }}
    >
      <PriceCell value={level.price} decimals={decimals} side={side} />
      <PriceCell value={level.size} decimals={sizeDecimals} side="neutral" />
      <PriceCell value={level.total} decimals={sizeDecimals} side="neutral" />
    </div>
  );
});

