export interface TreeNode { path: string; name: string; kind: 'file' | 'dir'; children?: ReadonlyArray<TreeNode>; }
export type Mode = 'normal' | 'visual' | 'search';

// flatten.ts — convert tree to visible flat list respecting expanded set
import type { TreeNode } from './types';
export function flatten(root: ReadonlyArray<TreeNode>, expanded: Set<string>, depth = 0): Array<{ node: TreeNode; depth: number }> {
  const out: Array<{ node: TreeNode; depth: number }> = [];
  for (const n of root) {
    out.push({ node: n, depth });
    if (n.kind === 'dir' && expanded.has(n.path) && n.children) out.push(...flatten(n.children, expanded, depth + 1));
  }
  return out;
}

// FileTree.tsx
import { useCallback, useMemo, useState, useRef, useEffect } from 'react';
import type { TreeNode, Mode } from './types';
import { flatten } from './flatten';

interface Props { root: ReadonlyArray<TreeNode>; onOpen: (path: string) => void; onDelete?: (paths: ReadonlyArray<string>) => void; showRelativeLines?: boolean; }

export function FileTree({ root, onOpen, onDelete, showRelativeLines = false }: Props) {
  const [expanded, setExpanded] = useState<Set<string>>(new Set());
  const [focusIdx, setFocusIdx] = useState(0);
  const [mode, setMode] = useState<Mode>('normal');
  const [anchorIdx, setAnchorIdx] = useState<number | null>(null);
  const [filter, setFilter] = useState('');
  const countBuffer = useRef('');
  const visible = useMemo(() => flatten(root, expanded), [root, expanded]);
  const treeRef = useRef<HTMLDivElement | null>(null);

  useEffect(() => { treeRef.current?.focus(); }, []);

  const selectedRange = (): [number, number] | null => {
    if (mode !== 'visual' || anchorIdx == null) return null;
    return [Math.min(anchorIdx, focusIdx), Math.max(anchorIdx, focusIdx)];
  };

  const onKey = useCallback((e: React.KeyboardEvent) => {
    if (mode === 'search') {
      if (e.key === 'Escape') { setMode('normal'); }
      else if (e.key === 'Enter') { setMode('normal'); const f = visible[focusIdx]; if (f && f.node.kind === 'file') onOpen(f.node.path); }
      return;
    }
    if (e.key === 'Escape') { setMode('normal'); setAnchorIdx(null); countBuffer.current = ''; return; }
    if (e.key === '/') { e.preventDefault(); setMode('search'); return; }
    if (e.key === 'V' && e.shiftKey) { e.preventDefault(); setMode('visual'); setAnchorIdx(focusIdx); return; }
    if (e.key >= '0' && e.key <= '9' && mode === 'normal') { countBuffer.current += e.key; return; }
    const count = Math.max(1, parseInt(countBuffer.current || '1', 10));
    if (e.key === 'j') { e.preventDefault(); setFocusIdx(i => Math.min(visible.length - 1, i + count)); }
    else if (e.key === 'k') { e.preventDefault(); setFocusIdx(i => Math.max(0, i - count)); }
    else if (e.key === 'h') {
      e.preventDefault();
      const cur = visible[focusIdx]; if (cur?.node.kind === 'dir' && expanded.has(cur.node.path)) {
        setExpanded(s => { const n = new Set(s); n.delete(cur.node.path); return n; });
      }
    }
    else if (e.key === 'l' || e.key === 'o') {
      e.preventDefault();
      const cur = visible[focusIdx];
      if (!cur) return;
      if (cur.node.kind === 'dir') setExpanded(s => { const n = new Set(s); n.add(cur.node.path); return n; });
      else onOpen(cur.node.path);
    }
    else if (e.key === 'y' && mode === 'visual') {
      const range = selectedRange();
      if (range) { const paths = visible.slice(range[0], range[1] + 1).map(v => v.node.path).join('\n'); navigator.clipboard.writeText(paths); }
    }
    else if (e.key === 'd' && mode === 'visual' && onDelete) {
      const range = selectedRange();
      if (range) { const paths = visible.slice(range[0], range[1] + 1).map(v => v.node.path); if (confirm(`Delete ${paths.length} item${paths.length === 1 ? '' : 's'}?`)) onDelete(paths); }
    }
    countBuffer.current = '';
  }, [mode, focusIdx, visible, expanded, onOpen, onDelete]);

  const range = selectedRange();
  const matchesFilter = (path: string) => !filter || path.toLowerCase().split('').filter(c => filter.toLowerCase().includes(c)).length === filter.length;

  return (
    <div className="bg-[oklch(0.18_0.005_250)] text-[oklch(0.85_0.005_250)] font-mono w-[260px] outline-none" tabIndex={0} ref={treeRef} onKeyDown={onKey} aria-label="File tree" role="tree">
      <header className="flex items-center justify-between px-2 py-1.5 text-[11px] uppercase tracking-wider border-b border-[oklch(0.25_0.005_250)]">
        <span>Files</span>
        <span className={`px-1.5 py-0.5 rounded text-[10px] transition-colors duration-[80ms] ${mode === 'normal' ? 'bg-[oklch(0.5_0.01_250)]' : mode === 'visual' ? 'bg-[oklch(0.6_0.16_50)]' : 'bg-[oklch(0.55_0.16_250)]'}`}>{mode === 'normal' ? 'N' : mode === 'visual' ? 'V' : '/'}</span>
      </header>
      {mode === 'search' && (
        <input autoFocus value={filter} onChange={(e) => setFilter(e.target.value)} placeholder="fuzzy filter…" className="w-full bg-[oklch(0.22_0.01_250)] px-2 py-1 text-[12px] outline-none" />
      )}
      <div className="py-1">
        {visible.map((v, i) => {
          const isFocus = i === focusIdx;
          const isInRange = range != null && i >= range[0] && i <= range[1];
          const matches = matchesFilter(v.node.path);
          return (
            <div key={v.node.path} role="treeitem" aria-selected={isFocus} aria-expanded={v.node.kind === 'dir' ? expanded.has(v.node.path) : undefined}
                 className={`flex items-center h-[22px] text-[12px] cursor-pointer ${isInRange ? 'bg-[oklch(0.35_0.06_50)]' : isFocus ? 'bg-[oklch(0.28_0.01_250)]' : ''} ${matches ? '' : 'opacity-30'}`}
                 style={{ paddingLeft: 8 + v.depth * 12 }}
                 onClick={() => { setFocusIdx(i); if (v.node.kind === 'file') onOpen(v.node.path); }}>
              {showRelativeLines && (
                <span className="w-6 text-right pr-2 tabular-nums text-[oklch(0.45_0.005_250)]">{isFocus ? 0 : Math.abs(i - focusIdx)}</span>
              )}
              <span className="truncate">{v.node.kind === 'dir' ? (expanded.has(v.node.path) ? '\u25BE' : '\u25B8') : '\u00B7'} {v.node.name}</span>
            </div>
          );
        })}
      </div>
    </div>
  );
}

