// CollaborativeField.tsx
import { useEffect, useState, useRef, useContext } from 'react';
import { PresenceCtx, useFieldPresence, colorFor } from './PresenceContext';
import { useFieldHistory } from './HistoryContext';

interface Props<V extends string | number> { id: string; value: V; onChange: (v: V) => void; label: string; coerce: (raw: string) => V; }

export function CollaborativeField<V extends string | number>({ id, value, onChange, label, coerce }: Props<V>) {
  const presence = useFieldPresence(id);
  const history = useFieldHistory<V>(id);
  const { localUserId } = useContext(PresenceCtx);
  const others = presence.filter(p => p.userId !== localUserId);
  const inputRef = useRef<HTMLInputElement | null>(null);
  const lastSeenRemoteValue = useRef<V>(value);
  const [recentRemoteChange, setRecentRemoteChange] = useState<{ author: string; colorIndex: number } | null>(null);

  // Detect remote change
  useEffect(() => {
    if (value !== lastSeenRemoteValue.current) {
      const last = history[0];
      if (last && last.author.id !== localUserId) {
        setRecentRemoteChange({ author: last.author.name, colorIndex: presence.find(p => p.userId === last.author.id)?.colorIndex ?? 0 });
        const t = window.setTimeout(() => setRecentRemoteChange(null), 8000);
        // preserve cursor position
        const el = inputRef.current;
        if (el && document.activeElement === el) {
          const oldLen = String(lastSeenRemoteValue.current).length;
          const newLen = String(value).length;
          const offset = newLen - oldLen;
          const sel = el.selectionStart ?? 0;
          requestAnimationFrame(() => { try { el.setSelectionRange(sel + offset, sel + offset); } catch {} });
        }
        return () => window.clearTimeout(t);
      }
      lastSeenRemoteValue.current = value;
    }
  }, [value, history, localUserId, presence]);

  const now = Date.now();
  const activeOther = others.find(o => now - o.lastTypedAt < 2000);
  const idleOther = others.find(o => now - o.lastTypedAt >= 2000);
  const ringColor = activeOther ? colorFor(activeOther.colorIndex) : idleOther ? colorFor(idleOther.colorIndex) : 'transparent';
  const ringOpacity = activeOther ? 1 : idleOther ? 0.5 : 0;

  return (
    <div className="relative mb-4">
      <label htmlFor={id} className="block text-[13px] font-medium text-[oklch(0.3_0.01_250)] mb-1.5">{label}</label>
      <div className="relative">
        <input id={id} ref={inputRef} value={String(value)} onChange={(e) => onChange(coerce(e.target.value))}
               aria-describedby={recentRemoteChange ? `${id}-rc` : undefined}
               className="w-full h-9 px-3 text-[14px] rounded-md bg-white outline-none border border-[oklch(0.85_0.005_250)] focus:border-[oklch(0.55_0.18_250)]"
               style={{ boxShadow: ringOpacity > 0 ? `0 0 0 2px ${ringColor.replace(')', ` / ${ringOpacity})`)}` : undefined, transition: 'box-shadow 150ms ease-out' }} />
        {(activeOther || idleOther) && (
          <span className="absolute -top-2 right-2 px-1.5 py-0.5 rounded text-[10px] font-medium text-white" style={{ background: ringColor }}>
            {activeOther ? `${activeOther.userName} typing` : (idleOther ? idleOther.userName : '')}
          </span>
        )}
      </div>
      {recentRemoteChange && (
        <div id={`${id}-rc`} role="status" aria-live="polite" className="mt-1 text-[11px] flex items-center gap-2" style={{ color: colorFor(recentRemoteChange.colorIndex) }}>
          Changed by {recentRemoteChange.author}
          {history[1] && <button type="button" onClick={() => onChange(history[1].value)} className="underline underline-offset-2 hover:no-underline text-[oklch(0.55_0.005_250)]">Undo</button>}
        </div>
      )}
    </div>
  );
}

import { useCallback, useEffect, useRef, useState } from 'react';

interface Result { onPointerDown: (e: React.PointerEvent) => void; onPointerUp: (e: React.PointerEvent) => void; onPointerLeave: (e: React.PointerEvent) => void; chargeFraction: number; isCharging: boolean; }

export function useChargePress(opts: { onClick: () => void; onSuperFire: () => void; chargeDurationMs?: number }): Result {
  const { onClick, onSuperFire, chargeDurationMs = 1000 } = opts;
  const startRef = useRef<number | null>(null);
  const rafRef = useRef<number | null>(null);
  const firedSuper = useRef(false);
  const hapticDone = useRef(false);
  const [chargeFraction, setChargeFraction] = useState(0);
  const [isCharging, setIsCharging] = useState(false);

  const tick = useCallback(() => {
    if (startRef.current == null) return;
    const elapsed = performance.now() - startRef.current;
    const f = Math.min(1, elapsed / chargeDurationMs);
    setChargeFraction(f);
    if (f >= 1 && !hapticDone.current) { hapticDone.current = true; if ('vibrate' in navigator) navigator.vibrate(12); }
    rafRef.current = requestAnimationFrame(tick);
  }, [chargeDurationMs]);

  const onPointerDown = useCallback((e: React.PointerEvent) => {
    (e.currentTarget as Element).setPointerCapture(e.pointerId);
    startRef.current = performance.now();
    firedSuper.current = false;
    hapticDone.current = false;
    setIsCharging(true);
    rafRef.current = requestAnimationFrame(tick);
  }, [tick]);

  const endGesture = useCallback(() => {
    if (rafRef.current) cancelAnimationFrame(rafRef.current);
    if (startRef.current == null) return;
    const elapsed = performance.now() - startRef.current;
    startRef.current = null;
    setIsCharging(false);
    if (elapsed < 150) { onClick(); setChargeFraction(0); return; }
    const finalFraction = Math.min(1, elapsed / chargeDurationMs);
    if (finalFraction >= 1 && !firedSuper.current) { firedSuper.current = true; onSuperFire(); }
    setChargeFraction(0);
  }, [onClick, onSuperFire, chargeDurationMs]);

  const onPointerUp = endGesture;
  const onPointerLeave = endGesture;

  useEffect(() => () => { if (rafRef.current) cancelAnimationFrame(rafRef.current); }, []);
  return { onPointerDown, onPointerUp, onPointerLeave, chargeFraction, isCharging };
}

// AnimatedCount.tsx — paper-tape per-digit
import { useEffect, useRef, useState } from 'react';
export function AnimatedCount({ value }: { value: number }) {
  const prev = useRef(value);
  const [shown, setShown] = useState(value);
  useEffect(() => {
    if (value === prev.current) return;
    setShown(value);
    prev.current = value;
  }, [value]);
  const digits = String(shown).split('');
  return (
    <span className="font-medium tabular-nums text-[13px] inline-flex" aria-live="polite">
      {digits.map((d, i) => (
        <span key={`${i}-${d}`} style={{ animation: 'paperTape 200ms cubic-bezier(0.22, 1, 0.36, 1)', display: 'inline-block' }}>{d}</span>
      ))}
      <style>{`@keyframes paperTape { 0% { transform: translateY(8px); opacity: 0 } 80% { transform: translateY(-1px); opacity: 1 } 100% { transform: translateY(0); opacity: 1 } } @media (prefers-reduced-motion: reduce) { [style*='paperTape'] { animation: none !important } }`}</style>
    </span>
  );
}

