interface Props { count: number; liked: boolean; onLike: (kind: 'regular' | 'super') => void; }

export function ReactionButton({ count, liked, onLike }: Props) {
  const [haloPulse, setHaloPulse] = useState(false);
  const { onPointerDown, onPointerUp, onPointerLeave, chargeFraction, isCharging } = useChargePress({
    onClick: () => onLike('regular'),
    onSuperFire: () => { onLike('super'); setHaloPulse(true); window.setTimeout(() => setHaloPulse(false), 600); },
  });
  const fillDeg = chargeFraction * 360;
  return (
    <button type="button" onPointerDown={onPointerDown} onPointerUp={onPointerUp} onPointerLeave={onPointerLeave}
            aria-label={liked ? `Unlike (${count})` : `Like. Hold to super-like (${count})`}
            aria-pressed={liked}
            className="relative inline-flex items-center gap-3 select-none touch-manipulation">
      <span className="relative w-9 h-9 rounded-full flex items-center justify-center transition-colors" style={{ background: isCharging ? `conic-gradient(oklch(0.65 0.18 25 / 0.25) ${fillDeg}deg, transparent ${fillDeg}deg)` : 'transparent', boxShadow: haloPulse ? '0 0 16px 2px oklch(0.65 0.18 25 / 0.4)' : 'none' }}>
        <svg width="18" height="18" viewBox="0 0 18 18" style={{ color: liked || isCharging ? 'oklch(0.65 0.18 25)' : 'oklch(0.5 0.005 250)' }}>
          <path d="M9 16 C 2 11 2 4 6 4 C 7.5 4 9 5.5 9 6.5 C 9 5.5 10.5 4 12 4 C 16 4 16 11 9 16 Z" fill={liked || haloPulse ? 'currentColor' : 'none'} stroke="currentColor" strokeWidth="1.5" />
        </svg>
        {haloPulse && <ParticleBurst />}
      </span>
      <AnimatedCount value={count} />
    </button>
  );
}

function ParticleBurst() {
  return (
    <span aria-hidden="true" className="absolute inset-0 pointer-events-none">
      {Array.from({ length: 8 }).map((_, i) => {
        const angle = (i / 8) * Math.PI * 2;
        const tx = Math.cos(angle) * 16;
        const ty = Math.sin(angle) * 16;
        return <span key={i} className="absolute top-1/2 left-1/2 w-1 h-1 rounded-full bg-[oklch(0.65_0.18_25)]" style={{ animation: 'particleOut 400ms cubic-bezier(0, 0, 0.2, 1) forwards', ['--tx' as string]: `${tx}px`, ['--ty' as string]: `${ty}px` } as React.CSSProperties} />;
      })}
      <style>{`@keyframes particleOut { from { transform: translate(-50%, -50%); opacity: 1 } to { transform: translate(calc(-50% + var(--tx)), calc(-50% + var(--ty))); opacity: 0 } } @media (prefers-reduced-motion: reduce) { [style*='particleOut'] { animation: none !important; opacity: 0 } }`}</style>
    </span>
  );
}

