// useFlip.ts — capture & invert for choreographed resize
import { useLayoutEffect, useRef } from 'react';
export function useFlip(key: string | number) {
  const elRef = useRef<HTMLDivElement | null>(null);
  const lastBoxRef = useRef<DOMRect | null>(null);
  useLayoutEffect(() => {
    const el = elRef.current;
    if (!el) return;
    const newBox = el.getBoundingClientRect();
    if (lastBoxRef.current) {
      const dx = lastBoxRef.current.left - newBox.left;
      const sx = lastBoxRef.current.width / newBox.width;
      el.style.transformOrigin = '0 0';
      el.style.transform = `translateX(${dx}px) scaleX(${sx})`;
      el.style.transition = 'none';
      requestAnimationFrame(() => {
        el.style.transition = 'transform 250ms cubic-bezier(0.22, 1, 0.36, 1)';
        el.style.transform = 'translateX(0) scaleX(1)';
      });
    }
    lastBoxRef.current = newBox;
  }, [key]);
  return elRef;
}

// FunnelChart.tsx
import { useMemo, useState } from 'react';
import type { FunnelStep, FunnelSegment } from './types';
import { useFlip } from './useFlip';

const SEG_COLORS: Record<string, string> = {};
const PALETTE = ['oklch(0.65 0.18 25)','oklch(0.6 0.18 145)','oklch(0.65 0.18 60)','oklch(0.6 0.18 280)','oklch(0.65 0.18 200)','oklch(0.7 0.16 320)','oklch(0.6 0.18 100)','oklch(0.7 0.15 240)'];
function colorFor(segId: string): string {
  if (!SEG_COLORS[segId]) {
    const idx = Object.keys(SEG_COLORS).length % PALETTE.length;
    SEG_COLORS[segId] = PALETTE[idx];
  }
  return SEG_COLORS[segId];
}

interface Props<S extends FunnelStep> { steps: ReadonlyArray<S>; }

export function FunnelChart<S extends FunnelStep>({ steps }: Props<S>) {
  const [filter, setFilter] = useState<string | null>(null);
  const maxCount = useMemo(() => Math.max(...steps.map(s => s.count), 1), [steps]);
  const filteredSteps = useMemo(() => filter ? steps.map(s => ({ ...s, count: s.segments.find(g => g.id === filter)?.count ?? 0, segments: s.segments.filter(g => g.id === filter) })) : steps, [steps, filter]);
  return (
    <div className="max-w-[600px]">
      {filter && (
        <div className="mb-3 flex items-center gap-2 text-[12px] text-[oklch(0.45_0.005_250)]">
          <span>Filtered to:</span>
          <button onClick={() => setFilter(null)} className="px-2 py-0.5 rounded-full border" style={{ borderColor: colorFor(filter), color: colorFor(filter) }}>{filter} \u00D7</button>
        </div>
      )}
      {filteredSteps.map((step, i) => {
        const next = filteredSteps[i + 1];
        const dropOff = next ? step.count - next.count : 0;
        const dropOffPct = step.count > 0 ? (dropOff / step.count) * 100 : 0;
        return (
          <div key={step.id}>
            <FunnelStepRow step={step} maxCount={maxCount} filter={filter} onSegmentClick={(seg) => setFilter(filter === seg.id ? null : seg.id)} />
            {next && dropOff > 0 && (
              <DropOffArrow dropOff={dropOff} pct={dropOffPct} reasons={step.dropOffReasons ?? []} />
            )}
          </div>
        );
      })}
    </div>
  );
}

function FunnelStepRow<S extends FunnelStep>({ step, maxCount, filter, onSegmentClick }: { step: S; maxCount: number; filter: string | null; onSegmentClick: (s: FunnelSegment) => void }) {
  const widthPct = (step.count / maxCount) * 100;
  const flipRef = useFlip(widthPct);
  return (
    <div>
      <div className="flex items-baseline justify-between mb-1">
        <span className="text-[13px] font-medium text-[oklch(0.2_0.01_250)]">{step.name}</span>
        <span className="text-[12px] tabular-nums text-[oklch(0.45_0.005_250)]">{step.count.toLocaleString()} <span className="text-[oklch(0.55_0.005_250)]">({((step.count / maxCount) * 100).toFixed(1)}%)</span></span>
      </div>
      <div ref={flipRef} className="h-8 bg-[oklch(0.96_0.005_250)] rounded overflow-hidden flex" style={{ width: `${widthPct}%`, minWidth: 80 }}>
        {step.segments.map(seg => {
          const segWidthPct = step.count > 0 ? (seg.count / step.count) * 100 : 0;
          const isFiltered = filter === seg.id;
          return (
            <button key={seg.id} type="button" onClick={() => onSegmentClick(seg)} aria-label={`${seg.label}: ${seg.count} users. ${isFiltered ? 'Filter active.' : 'Click to filter.'}`}
                    className="h-full hover:brightness-110 transition-[filter] duration-[80ms] relative"
                    style={{ width: `${segWidthPct}%`, background: colorFor(seg.id), outline: isFiltered ? `2px solid ${colorFor(seg.id)}` : 'none', outlineOffset: 1 }} />
          );
        })}
      </div>
    </div>
  );
}

function DropOffArrow({ dropOff, pct, reasons }: { dropOff: number; pct: number; reasons: ReadonlyArray<{ reason: string; share: number }> }) {
  const [open, setOpen] = useState(false);
  return (
    <div className="my-3 ml-4 pl-3 border-l border-dashed border-[oklch(0.75_0.005_250)] text-[11px] text-[oklch(0.45_0.005_250)] italic">
      <button type="button" onClick={() => setOpen(o => !o)} className="hover:text-[oklch(0.3_0.005_250)] not-italic">
        \u2193 {dropOff.toLocaleString()} dropped off ({pct.toFixed(1)}%)
        {reasons.length > 0 && <span className="ml-2">{open ? '\u2212' : '+'}</span>}
      </button>
      {open && reasons.length > 0 && (
        <ul className="mt-1 ml-2 list-none not-italic text-[12px] text-[oklch(0.4_0.005_250)]">
          {reasons.slice(0, 3).map(r => (
            <li key={r.reason}><span className="inline-block w-8 text-right tabular-nums text-[oklch(0.55_0.005_250)]">{(r.share * 100).toFixed(0)}%</span> &nbsp; {r.reason}</li>
          ))}
        </ul>
      )}
    </div>
  );
}

