// adopt-on-edit.ts
export function detectAdoptionAfterEdit(issue: Issue, beforeTitle: string, beforeBody: string): Issue {
  if (!issue.isSample || issue.adoptionLevel === 'adopted') return issue;
  if (issue.title !== beforeTitle || issue.body !== beforeBody) {
    return { ...issue, adoptionLevel: 'adopted', isSample: false, lastInteractionAt: Date.now() };
  }
  return issue;
}

// sample-archival.ts
export function archiveStaleSamples(issues: ReadonlyArray<Issue>, now = Date.now()): { keep: ReadonlyArray<Issue>; archive: ReadonlyArray<Issue> } {
  const SEVEN_DAYS = 7 * 86400_000;
  const archive: Issue[] = [];
  const keep: Issue[] = [];
  for (const i of issues) {
    if (i.isSample && i.adoptionLevel === 'untouched' && now - i.createdAt > SEVEN_DAYS) archive.push(i);
    else keep.push(i);
  }
  return { keep, archive };
}

export interface ParsedRange { start: Date; end: Date; presetId?: string; }

function startOfDay(d: Date): Date { const n = new Date(d); n.setHours(0, 0, 0, 0); return n; }
function endOfDay(d: Date): Date { const n = new Date(d); n.setHours(23, 59, 59, 999); return n; }
function addDays(d: Date, n: number): Date { const r = new Date(d); r.setDate(r.getDate() + n); return r; }

export function parseRange(input: string, now = new Date()): ParsedRange | null {
  const s = input.trim().toLowerCase();
  if (!s) return null;
  if (s === 'today') return { start: startOfDay(now), end: endOfDay(now), presetId: 'today' };
  if (s === 'yesterday') { const y = addDays(now, -1); return { start: startOfDay(y), end: endOfDay(y), presetId: 'yesterday' }; }
  const lastN = s.match(/^last (\d+) (day|days|week|weeks|month|months)$/);
  if (lastN) {
    const n = parseInt(lastN[1], 10);
    const unit = lastN[2];
    const days = unit.startsWith('week') ? n * 7 : unit.startsWith('month') ? n * 30 : n;
    return { start: startOfDay(addDays(now, -days + 1)), end: endOfDay(now), presetId: `last-${days}-days` };
  }
  if (s === 'this month') { const start = new Date(now.getFullYear(), now.getMonth(), 1); return { start: startOfDay(start), end: endOfDay(now), presetId: 'month-to-date' }; }
  if (s === 'last month') { const start = new Date(now.getFullYear(), now.getMonth() - 1, 1); const end = new Date(now.getFullYear(), now.getMonth(), 0); return { start: startOfDay(start), end: endOfDay(end), presetId: 'last-month' }; }
  const q = s.match(/^q([1-4])(?: (\d{4}))?$/);
  if (q) { const qn = parseInt(q[1], 10); const year = q[2] ? parseInt(q[2], 10) : now.getFullYear(); const startMonth = (qn - 1) * 3; const start = new Date(year, startMonth, 1); const end = new Date(year, startMonth + 3, 0); return { start: startOfDay(start), end: endOfDay(end), presetId: `q${qn}-${year}` }; }
  const iso = s.match(/^(\d{4}-\d{2}-\d{2})(?: to (\d{4}-\d{2}-\d{2}))?$/);
  if (iso) { const start = new Date(iso[1]); if (isNaN(start.getTime())) return null; if (!iso[2]) return { start: startOfDay(start), end: endOfDay(start) }; const end = new Date(iso[2]); if (isNaN(end.getTime())) return null; return { start: startOfDay(start), end: endOfDay(end) }; }
  return null;
}

