import { useCallback, useMemo, useState } from 'react';
import { parseRange, type ParsedRange } from './parse';

const PRESETS = [
  { id: 'today', label: 'Today', expr: 'today' },
  { id: 'yesterday', label: 'Yesterday', expr: 'yesterday' },
  { id: 'last-7-days', label: 'Last 7 days', expr: 'last 7 days' },
  { id: 'last-30-days', label: 'Last 30 days', expr: 'last 30 days' },
  { id: 'month-to-date', label: 'Month to date', expr: 'this month' },
  { id: 'last-month', label: 'Last month', expr: 'last month' },
] as const;

interface Props { value: ParsedRange | null; onChange: (r: ParsedRange | null) => void; }

export function DateRangePicker({ value, onChange }: Props) {
  const [input, setInput] = useState(value ? formatRange(value) : '');
  const [pending, setPending] = useState<ParsedRange | null>(value);
  const parsed = useMemo(() => input ? parseRange(input) : value, [input, value]);
  const error = input && !parsed;

  const commit = useCallback(() => { if (parsed) onChange(parsed); }, [parsed, onChange]);

  const visible = parsed ?? pending ?? value;

  return (
    <div className="w-[620px] bg-white rounded-lg shadow-lg p-4" role="dialog" aria-label="Date range picker" style={{ animation: 'pickerIn 120ms cubic-bezier(0, 0, 0.2, 1)' }}>
      <input value={input} onChange={(e) => setInput(e.target.value)} onKeyDown={(e) => { if (e.key === 'Enter') commit(); }} onBlur={commit}
             placeholder="last 7 days, q1 2024, 2024-01-01 to 2024-03-31\u2026"
             aria-invalid={!!error} aria-label="Type or pick a date range"
             className={`w-full h-9 px-3 text-[14px] border-b ${error ? 'border-[oklch(0.6_0.18_25)]' : 'border-[oklch(0.85_0.005_250)]'} outline-none mb-4`} />
      <div className="flex gap-4">
        <div className="w-[140px] flex flex-col gap-1">
          {PRESETS.map(p => {
            const active = visible?.presetId === p.id;
            return (
              <button key={p.id} type="button" onClick={() => setInput(p.expr)} className={`text-left px-2 py-1.5 rounded text-[13px] ${active ? 'bg-[oklch(0.94_0.01_250)] text-[oklch(0.2_0.01_250)] font-medium' : 'text-[oklch(0.4_0.005_250)] hover:bg-[oklch(0.96_0.005_250)]'}`}>{p.label}</button>
            );
          })}
        </div>
        <div className="flex-1"><DualMonthCalendar range={visible} onPickRange={(r) => { setPending(r); setInput(formatRange(r)); }} /></div>
      </div>
      <div className="mt-3 text-[11px] text-[oklch(0.55_0.005_250)] text-right">Timezone: {Intl.DateTimeFormat().resolvedOptions().timeZone}</div>
      <style>{`@keyframes pickerIn { from { opacity: 0; transform: translateY(4px) } to { opacity: 1; transform: translateY(0) } } @media (prefers-reduced-motion: reduce) { [style*='pickerIn'] { animation: none !important } }`}</style>
    </div>
  );
}

function formatRange(r: ParsedRange): string {
  const fmt = (d: Date) => d.toISOString().slice(0, 10);
  return fmt(r.start) === fmt(r.end) ? fmt(r.start) : `${fmt(r.start)} to ${fmt(r.end)}`;
}

function DualMonthCalendar({ range, onPickRange }: { range: ParsedRange | null; onPickRange: (r: ParsedRange) => void }) {
  const [hoverEnd, setHoverEnd] = useState<Date | null>(null);
  const [pickStart, setPickStart] = useState<Date | null>(null);
  const now = new Date();
  return (
    <div className="flex gap-4">
      {[0, 1].map(offset => (
        <MonthGrid key={offset} year={now.getFullYear()} month={now.getMonth() + offset} range={range} hoverEnd={hoverEnd} pickStart={pickStart}
          onCellHover={setHoverEnd}
          onCellClick={(d) => {
            if (!pickStart) { setPickStart(d); }
            else { const start = pickStart < d ? pickStart : d; const end = pickStart < d ? d : pickStart; onPickRange({ start, end }); setPickStart(null); setHoverEnd(null); }
          }} />
      ))}
    </div>
  );
}

function MonthGrid({ year, month, range, hoverEnd, pickStart, onCellHover, onCellClick }: { year: number; month: number; range: ParsedRange | null; hoverEnd: Date | null; pickStart: Date | null; onCellHover: (d: Date | null) => void; onCellClick: (d: Date) => void }) {
  const first = new Date(year, month, 1);
  const days = new Date(year, month + 1, 0).getDate();
  const leadingBlanks = first.getDay();
  const cells: Array<Date | null> = [];
  for (let i = 0; i < leadingBlanks; i++) cells.push(null);
  for (let d = 1; d <= days; d++) cells.push(new Date(year, month, d));
  const inRange = (d: Date): boolean => {
    if (pickStart && hoverEnd) { const lo = pickStart < hoverEnd ? pickStart : hoverEnd; const hi = pickStart < hoverEnd ? hoverEnd : pickStart; return d >= lo && d <= hi; }
    if (range) return d >= range.start && d <= range.end;
    return false;
  };
  return (
    <div className="w-[224px]">
      <div className="text-[13px] font-medium mb-2 text-center">{first.toLocaleString('default', { month: 'long', year: 'numeric' })}</div>
      <div className="grid grid-cols-7 gap-0">
        {['S','M','T','W','T','F','S'].map((d, i) => <div key={i} className="text-[10px] uppercase tracking-wider text-[oklch(0.55_0.005_250)] text-center pb-1">{d}</div>)}
        {cells.map((d, i) => {
          if (!d) return <div key={i} />;
          const isStart = range && d.getTime() === range.start.getTime();
          const isEnd = range && d.getTime() === range.end.getTime();
          const within = inRange(d);
          return (
            <button key={i} type="button" onMouseEnter={() => onCellHover(d)} onClick={() => onCellClick(d)}
              className={`h-8 text-[13px] tabular-nums transition-[background] duration-[80ms] ${within ? 'bg-[oklch(0.92_0.05_250)]' : 'hover:bg-[oklch(0.96_0.005_250)]'} ${isStart || isEnd ? 'rounded-md bg-[oklch(0.55_0.18_250)] text-white' : ''}`}
              aria-label={d.toDateString()}>{d.getDate()}</button>
          );
        })}
      </div>
    </div>
  );
}

