import { createContext, useContext, useState } from 'react';
interface Ctx { focusId: string | null; setFocusId: (id: string | null) => void; neighbors: Set<string>; setNeighbors: (s: Set<string>) => void; }
const C = createContext<Ctx | null>(null);
export function FocusProvider({ children }: { children: React.ReactNode }) {
  const [focusId, setFocusId] = useState<string | null>(null);
  const [neighbors, setNeighbors] = useState<Set<string>>(new Set());
  return <C.Provider value={{ focusId, setFocusId, neighbors, setNeighbors }}>{children}</C.Provider>;
