// FocusCamera.tsx
import { useFrame, useThree } from '@react-three/fiber';
import { useFocus } from './FocusContext';
import { Vector3 } from 'three';
import { useEffect, useRef } from 'react';
import type { ServiceNode } from './types';

export function FocusCamera({ nodes }: { nodes: ReadonlyArray<ServiceNode> }) {
  const { focusId } = useFocus();
  const { camera, invalidate } = useThree();
  const target = useRef(new Vector3(0, 4, 12));
  const lookAt = useRef(new Vector3(0, 0, 0));
  useEffect(() => {
    if (!focusId) { target.current.set(0, 4, 12); lookAt.current.set(0, 0, 0); invalidate(); return; }
    const n = nodes.find(x => x.id === focusId);
    if (!n) return;
    target.current.set(n.position[0] + 2, n.position[1] + 1.5, n.position[2] + 3.5);
    lookAt.current.set(...n.position);
    invalidate();
  }, [focusId, nodes, invalidate]);
  useFrame(() => {
    camera.position.lerp(target.current, 0.06);
    camera.lookAt(lookAt.current);
    if (camera.position.distanceTo(target.current) > 0.01) invalidate();
  });
  return null;
}

// InstancedNodes.tsx
import { useMemo, useRef, useEffect } from 'react';
import { InstancedMesh, Object3D, Color } from 'three';
import type { ServiceNode } from './types';
import { useFocus } from './FocusContext';

const STATUS_COLOR: Record<ServiceNode['status'], string> = { green: '#3fbf6f', yellow: '#e0b13a', red: '#d4524d' };

export function InstancedNodes({ nodes, onNodeClick }: { nodes: ReadonlyArray<ServiceNode>; onNodeClick: (id: string) => void }) {
  const meshRef = useRef<InstancedMesh>(null);
  const dummy = useMemo(() => new Object3D(), []);
  const { focusId, neighbors } = useFocus();

  useEffect(() => {
    if (!meshRef.current) return;
    nodes.forEach((n, i) => {
      dummy.position.set(...n.position);
      const scale = n.id === focusId ? 0.6 : 0.35;
      dummy.scale.setScalar(scale);
      dummy.updateMatrix();
      meshRef.current!.setMatrixAt(i, dummy.matrix);
      const baseColor = new Color(STATUS_COLOR[n.status]);
      const isFocus = n.id === focusId;
      const isNeighbor = neighbors.has(n.id);
      const dim = focusId && !isFocus && !isNeighbor ? 0.4 : 1.0;
      meshRef.current!.setColorAt(i, baseColor.multiplyScalar(dim));
    });
    meshRef.current.instanceMatrix.needsUpdate = true;
    if (meshRef.current.instanceColor) meshRef.current.instanceColor.needsUpdate = true;
  }, [nodes, dummy, focusId, neighbors]);

  return (
    <instancedMesh ref={meshRef} args={[undefined, undefined, nodes.length]}
      onClick={(e) => { e.stopPropagation(); const id = nodes[e.instanceId ?? 0]?.id; if (id) onNodeClick(id); }}>
      <sphereGeometry args={[1, 16, 12]} />
      <meshStandardMaterial roughness={0.6} metalness={0.1} />
    </instancedMesh>
  );
}

