export function TopologyMap({ nodes, edges }: { nodes: ReadonlyArray<ServiceNode>; edges: ReadonlyArray<ServiceEdge> }) {
  return (
    <FocusProvider>
      <div className="relative w-full h-screen bg-gradient-to-b from-[oklch(0.14_0.01_250)] to-[oklch(0.08_0.005_250)]">
        <Canvas frameloop="demand" dpr={[1, 1.5]} camera={{ position: [0, 4, 12], fov: 40 }}>
          <ambientLight intensity={0.5} />
          <directionalLight position={[5, 8, 5]} intensity={0.6} />
          <TopologyInner nodes={nodes} edges={edges} />
        </Canvas>
      </div>
    </FocusProvider>
  );
}

function TopologyInner({ nodes, edges }: { nodes: ReadonlyArray<ServiceNode>; edges: ReadonlyArray<ServiceEdge> }) {
  const { focusId, setFocusId, setNeighbors } = useFocus();
  const neighborMap = useMemo(() => {
    const m = new Map<string, Set<string>>();
    for (const e of edges) {
      if (!m.has(e.from)) m.set(e.from, new Set());
      if (!m.has(e.to)) m.set(e.to, new Set());
      m.get(e.from)!.add(e.to);
      m.get(e.to)!.add(e.from);
    }
    return m;
  }, [edges]);
  const onNodeClick = useCallback((id: string) => { setFocusId(id); setNeighbors(neighborMap.get(id) ?? new Set()); }, [setFocusId, setNeighbors, neighborMap]);
  const focusedNode = focusId ? nodes.find(n => n.id === focusId) : null;
  return (
    <>
      <FocusCamera nodes={nodes} />
      <InstancedNodes nodes={nodes} onNodeClick={onNodeClick} />
      {focusedNode && (
        <Html position={focusedNode.position} center transform={false} style={{ pointerEvents: 'none' }}>
          <div className="px-3 py-2 rounded-md bg-[oklch(0.18_0.005_250_/_0.92)] text-white text-[12px] backdrop-blur-md min-w-[140px]">
            <div className="font-medium text-[13px]">{focusedNode.name}</div>
            <div className="text-[10px] uppercase tracking-wider opacity-70 mt-0.5">{focusedNode.tier} \u00B7 {focusedNode.status}</div>
          </div>
        </Html>
      )}
    </>
  );
}

import { useState, useCallback } from 'react';
export interface PendingEvent { startMin: number; endMin: number; title: string; date: string; }
export function useCreateEvent() {
  const [pending, setPending] = useState<PendingEvent | null>(null);
  const start = useCallback((date: string, startMin: number, endMin: number) => setPending({ date, startMin, endMin, title: '' }), []);
  const updateRange = useCallback((endMin: number) => setPending(p => p ? { ...p, endMin } : null), []);
  const updateTitle = useCallback((title: string) => setPending(p => p ? { ...p, title } : null), []);
