  return { pending, start, updateRange, updateTitle, commit, cancel };
}

// DesktopDayView.tsx
import { useRef, useState, useEffect } from 'react';
import { useCreateEvent } from './useCreateEvent';

const HOUR_HEIGHT = 60;
const SLOT_QUARTER = 15;

export function DesktopDayView({ date }: { date: string }) {
  const { pending, start, updateRange, commit, cancel } = useCreateEvent();
  const containerRef = useRef<HTMLDivElement | null>(null);
  const dragging = useRef<{ anchorMin: number } | null>(null);
  const titleRef = useRef<HTMLInputElement | null>(null);

  useEffect(() => { if (pending) titleRef.current?.focus(); }, [pending]);

  const yToMin = (y: number) => {
    const slot = Math.round(y / (HOUR_HEIGHT / 4));
    return slot * SLOT_QUARTER;
  };

  const onDown = (e: React.MouseEvent) => {
    const rect = containerRef.current!.getBoundingClientRect();
    const y = e.clientY - rect.top;
    const m = yToMin(y);
    dragging.current = { anchorMin: m };
    start(date, m, m + 30);
  };
  const onMove = (e: React.MouseEvent) => {
    if (!dragging.current) return;
    const rect = containerRef.current!.getBoundingClientRect();
    const y = e.clientY - rect.top;
    const m = yToMin(y);
    const anchor = dragging.current.anchorMin;
    updateRange(Math.max(anchor + 15, m));
  };
  const onUp = () => { dragging.current = null; };

  return (
    <div ref={containerRef} className="relative bg-white" style={{ height: 24 * HOUR_HEIGHT }} onMouseDown={onDown} onMouseMove={onMove} onMouseUp={onUp}>
      {Array.from({ length: 24 }).map((_, h) => (
        <div key={h} className="absolute left-0 right-0 border-t border-[oklch(0.93_0.005_250)] text-[11px] tabular-nums text-[oklch(0.55_0.005_250)] pl-2 pt-0.5" style={{ top: h * HOUR_HEIGHT, height: HOUR_HEIGHT }}>{String(h).padStart(2, '0')}:00</div>
      ))}
      {pending && (
        <div className="absolute left-12 right-4 rounded-md bg-[oklch(0.55_0.18_250_/_0.8)] border border-[oklch(0.55_0.18_250)] text-white px-2 py-1" style={{ top: pending.startMin / 60 * HOUR_HEIGHT, height: (pending.endMin - pending.startMin) / 60 * HOUR_HEIGHT }}>
          <input ref={titleRef} value={pending.title} onChange={(e) => /* updateTitle */ null}
                 onKeyDown={(e) => { if (e.key === 'Enter' && e.metaKey) commit(); if (e.key === 'Escape') cancel(); }}
                 placeholder="Event title" className="w-full bg-transparent outline-none text-[13px] font-medium placeholder:text-white/70" />
          <div className="text-[11px] tabular-nums opacity-80">{fmt(pending.startMin)} \u2013 {fmt(pending.endMin)}</div>
        </div>
      )}
    </div>
  );
}

function fmt(min: number): string {
  const h = Math.floor(min / 60);
  const m = min % 60;
  return `${String(h).padStart(2, '0')}:${String(m).padStart(2, '0')}`;
}

