import { useEffect, useRef, useState } from 'react';
import { useCreateEvent } from './useCreateEvent';

export function MobileEventSheet({ date, initialStart, initialEnd, onClose }: { date: string; initialStart: number; initialEnd: number; onClose: () => void }) {
  const { pending, start: startEvent, updateTitle, commit, cancel } = useCreateEvent();
  const [translateY, setTranslateY] = useState(0);
  const dragRef = useRef<{ startY: number } | null>(null);
  const sheetRef = useRef<HTMLDivElement | null>(null);

  useEffect(() => { startEvent(date, initialStart, initialEnd); }, [date, initialStart, initialEnd, startEvent]);

  const onDown = (e: React.PointerEvent) => { dragRef.current = { startY: e.clientY }; (e.target as Element).setPointerCapture(e.pointerId); };
  const onMove = (e: React.PointerEvent) => { if (!dragRef.current) return; setTranslateY(Math.max(0, e.clientY - dragRef.current.startY)); };
  const onUp = () => {
    dragRef.current = null;
    if (translateY > 120) { cancel(); onClose(); }
    else setTranslateY(0);
  };

  if (!pending) return null;
  return (
    <div className="fixed inset-0 z-50 pointer-events-none">
      <div ref={sheetRef} role="dialog" aria-label="New event"
        className="absolute bottom-0 left-0 right-0 h-[40vh] bg-white rounded-t-2xl shadow-2xl pointer-events-auto"
        style={{ transform: `translateY(${translateY}px)`, transition: dragRef.current ? 'none' : 'transform 350ms cubic-bezier(0.32, 0.72, 0, 1)' }}>
        <div className="flex justify-center pt-2 pb-1 touch-none" onPointerDown={onDown} onPointerMove={onMove} onPointerUp={onUp}><div className="w-10 h-1 bg-[oklch(0.85_0.005_250)] rounded-full" /></div>
        <div className="px-4 pt-2">
          <input autoFocus value={pending.title} onChange={(e) => updateTitle(e.target.value)} placeholder="What\u2019s happening?" className="w-full text-[17px] outline-none placeholder:text-[oklch(0.55_0.005_250)]" />
          <div className="mt-2 text-[13px] text-[oklch(0.55_0.005_250)] tabular-nums">{fmt(pending.startMin)} \u2013 {fmt(pending.endMin)} on {date}</div>
          <button type="button" onClick={() => commit()} className="mt-4 w-full h-12 rounded-lg bg-[oklch(0.55_0.18_250)] text-white text-[15px] font-medium">Save</button>
        </div>
      </div>
    </div>
  );
}

import { useEffect, useRef } from 'react';
export function useRouteFocus<T extends HTMLElement>() {
  const ref = useRef<T | null>(null);
  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    if (!el.hasAttribute('tabindex')) el.setAttribute('tabindex', '-1');
    el.focus({ preventScroll: false });
    return () => { try { el.removeAttribute('tabindex'); } catch {} };
  }, []);
  return ref;
}

