import { createContext, useCallback, useContext, useRef } from 'react';
interface Stack { push: (el: HTMLElement | null) => void; pop: () => HTMLElement | null; }
const Ctx = createContext<Stack | null>(null);
export function FocusStackProvider({ children }: { children: React.ReactNode }) {
  const stack = useRef<Array<HTMLElement | null>>([]);
  const value: Stack = {
    push: (el) => { stack.current.push(el); },
    pop: () => stack.current.pop() ?? null,
  };
  return <Ctx.Provider value={value}>{children}</Ctx.Provider>;
}
export function useFocusStack(): Stack { const v = useContext(Ctx); if (!v) throw new Error('provider'); return v; }

// useFocusTrap.ts
import { useEffect, useRef } from 'react';
export function useFocusTrap<T extends HTMLElement>(active: boolean) {
  const ref = useRef<T | null>(null);
  useEffect(() => {
    if (!active) return;
    const root = ref.current;
    if (!root) return;
    const selector = 'a[href], button:not([disabled]), input:not([disabled]), select:not([disabled]), textarea:not([disabled]), [tabindex]:not([tabindex="-1"])';
    const onKey = (e: KeyboardEvent) => {
      if (e.key !== 'Tab') return;
      const focusables = Array.from(root.querySelectorAll<HTMLElement>(selector));
      if (focusables.length === 0) { e.preventDefault(); return; }
      const first = focusables[0]; const last = focusables[focusables.length - 1];
      const active = document.activeElement as HTMLElement | null;
      if (e.shiftKey && active === first) { e.preventDefault(); last.focus(); }
      else if (!e.shiftKey && active === last) { e.preventDefault(); first.focus(); }
    };
    document.addEventListener('keydown', onKey);
    return () => document.removeEventListener('keydown', onKey);
  }, [active]);
  return ref;
}

