import { useEffect, useRef } from 'react';
import { useFocusStack } from './FocusStackContext';
import { useFocusTrap } from './useFocusTrap';
import { useAnnounce } from './Announcer';

interface Props { open: boolean; onClose: () => void; title: string; children: React.ReactNode; }
export function Modal({ open, onClose, title, children }: Props) {
  const trapRef = useFocusTrap<HTMLDivElement>(open);
  const stack = useFocusStack();
  const titleId = useRef(`m-${Math.random().toString(36).slice(2, 9)}`).current;
  const announce = useAnnounce();

  useEffect(() => {
    if (!open) return;
    stack.push(document.activeElement as HTMLElement | null);
    announce(`${title} dialog opened`);
    const t = window.setTimeout(() => {
      const root = trapRef.current;
      const target = root?.querySelector<HTMLElement>('[data-autofocus], h2, button');
      target?.focus();
    }, 0);
    const onKey = (e: KeyboardEvent) => { if (e.key === 'Escape') onClose(); };
    document.addEventListener('keydown', onKey);
    return () => {
      document.removeEventListener('keydown', onKey);
      window.clearTimeout(t);
      const prev = stack.pop();
      prev?.focus();
    };
  }, [open, title, announce, stack, onClose, trapRef]);

  if (!open) return null;
  return (
    <div role="dialog" aria-modal="true" aria-labelledby={titleId} className="fixed inset-0 z-50 flex items-center justify-center bg-[oklch(0.18_0.005_250/0.6)]" onClick={onClose}>
      <div ref={trapRef} onClick={(e) => e.stopPropagation()} className="bg-white rounded-xl shadow-2xl p-6 min-w-[360px] max-w-[80vw]">
        <h2 id={titleId} className="text-[17px] font-medium mb-3">{title}</h2>
        {children}
      </div>
    </div>
  );
}

// Announcer.tsx — single polite + single assertive
import { createContext, useCallback, useContext, useRef, useState } from 'react';
interface Ctx { announce: (msg: string, urgency?: 'polite' | 'assertive') => void; }
const C = createContext<Ctx | null>(null);
export function AnnouncerProvider({ children }: { children: React.ReactNode }) {
  const [polite, setPolite] = useState('');
  const [assertive, setAssertive] = useState('');
  const debounceRef = useRef<number | null>(null);
  const announce = useCallback((msg: string, urgency: 'polite' | 'assertive' = 'polite') => {
    if (urgency === 'assertive') { setAssertive(msg); return; }
    if (debounceRef.current) window.clearTimeout(debounceRef.current);
    debounceRef.current = window.setTimeout(() => setPolite(msg), 200);
  }, []);
  return (
    <C.Provider value={{ announce }}>
      {children}
      <div role="status" aria-live="polite" aria-atomic="true" className="sr-only">{polite}</div>
      <div role="alert" aria-live="assertive" aria-atomic="true" className="sr-only">{assertive}</div>
    </C.Provider>
  );
}
export function useAnnounce() { const v = useContext(C); if (!v) throw new Error('provider'); return v.announce; }

