// useEagerLoadObserver.ts
import { useEffect, useRef, useState } from 'react';
export function useEagerLoadObserver<T extends HTMLElement>(rootMargin = '800px') {
  const ref = useRef<T | null>(null);
  const [shouldLoad, setShouldLoad] = useState(false);
  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    if (shouldLoad) return;
    const obs = new IntersectionObserver((entries) => {
      if (entries.some(e => e.isIntersecting)) {
        setShouldLoad(true);
        obs.disconnect();
      }
    }, { rootMargin });
    obs.observe(el);
    return () => obs.disconnect();
  }, [rootMargin, shouldLoad]);
  return { ref, shouldLoad };
}

// ImageSlot.tsx
import { useState } from 'react';
import { useEagerLoadObserver } from './useEagerLoadObserver';
import type { ImageRecord } from './types';

interface Props { image: ImageRecord; priority: 'high' | 'low' | 'defer'; }

export function ImageSlot({ image, priority }: Props) {
  const eager = useEagerLoadObserver<HTMLDivElement>('800px');
  const [loaded, setLoaded] = useState(false);
  const aspect = image.width / image.height;
  const willLoad = priority !== 'defer' || eager.shouldLoad;
  return (
    <div ref={eager.ref} className="relative bg-[oklch(0.95_0.005_250)] overflow-hidden rounded" style={{ aspectRatio: aspect, backgroundImage: `url(${image.lqipBase64})`, backgroundSize: 'cover', backgroundPosition: 'center' }}>
      <div aria-hidden="true" className="absolute inset-0" style={{ backdropFilter: loaded ? 'none' : 'blur(24px)', transition: 'backdrop-filter 0ms' }} />
      {willLoad && (
        <img
          src={image.src}
          srcSet={image.srcset}
          sizes={image.sizes}
          alt={image.alt}
          loading={priority === 'high' ? 'eager' : 'lazy'}
          fetchPriority={priority === 'high' ? 'high' : priority === 'low' ? 'low' : 'auto'}
          decoding="async"
          onLoad={() => setLoaded(true)}
          className="absolute inset-0 w-full h-full object-cover transition-opacity duration-[100ms]"
          style={{ opacity: loaded ? 1 : 0 }}
        />
      )}
    </div>
  );
}

// Gallery.tsx
import type { ImageRecord } from './types';
import { ImageSlot } from './ImageSlot';

export function Gallery<I extends ImageRecord>({ images }: { images: ReadonlyArray<I> }) {
  return (
    <ul className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-2" role="list">
      {images.map((img, i) => {
        // First 8 are high priority (likely visible), next 8 are low priority lazy, rest are deferred until IO
        const priority: 'high' | 'low' | 'defer' = i < 8 ? 'high' : i < 16 ? 'low' : 'defer';
        return (
          <li key={img.id} role="listitem">
            <ImageSlot image={img} priority={priority} />
          </li>
        );
      })}
    </ul>
  );
}

