import { useMemo, useState } from 'react';
import type { DirectoryEntry } from './types';

interface Props<E extends DirectoryEntry> { entries: ReadonlyArray<E>; categories: ReadonlyArray<{ code: string; label: string }>; }

export function Directory<E extends DirectoryEntry>({ entries, categories }: Props<E>) {
  const [active, setActive] = useState<Set<string>>(new Set());
  const visible = useMemo(() => active.size === 0 ? entries : entries.filter(e => active.has(e.categoryCode)), [entries, active]);
  const toggle = (code: string) => setActive(s => { const n = new Set(s); if (n.has(code)) n.delete(code); else n.add(code); return n; });

  return (
    <div className="min-h-screen" style={{ fontFamily: '-apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif' }}>
      <header className="border-b border-[var(--b-rule)] py-6 px-6">
        <h1 className="text-[18px] font-medium">Directory</h1>
        <p className="mt-2 text-[13px]" style={{ fontFamily: 'Times New Roman, Times, Georgia, serif', fontStyle: 'italic' }}>{visible.length} of {entries.length} entries</p>
      </header>
      <nav className="flex border-b border-[var(--b-rule)]" aria-label="Filter by category">
        {categories.map((c, i) => {
          const isOn = active.has(c.code);
          return (
            <button key={c.code} type="button" onClick={() => toggle(c.code)}
              aria-pressed={isOn}
              className="px-4 py-3 text-[11px] uppercase tracking-widest hover:bg-[var(--b-ink)] hover:text-[var(--b-paper)]"
              style={{ background: isOn ? 'var(--b-ink)' : 'transparent', color: isOn ? 'var(--b-paper)' : 'var(--b-ink)', borderLeft: i > 0 ? '0.5px solid var(--b-rule-thin)' : 'none' }}>
              {c.label} <span className="opacity-50 tabular-nums">/{c.code}</span>
            </button>
          );
        })}
      </nav>
      <ol className="list-none" role="list">
        {visible.map((e, i) => (
          <li key={e.id} role="listitem" className="grid grid-cols-12 items-center h-24 px-6 hover:bg-[var(--b-ink)] hover:text-[var(--b-paper)] border-b border-[var(--b-rule-thin)]">
            <span className="col-span-2 text-[64px] leading-none tabular-nums opacity-30 group-hover:opacity-60" style={{ fontFamily: 'Times New Roman, Times, Georgia, serif', fontStyle: 'italic', fontVariantNumeric: 'oldstyle-nums' }}>{String(i + 1).padStart(3, '0')}</span>
            <a href={`/entry/${e.id}`} className="col-span-5 text-[18px] font-medium underline" style={{ textDecorationThickness: '1px', textUnderlineOffset: '0.2em' }}>{e.title}</a>
            <span className="col-span-2 text-[13px]">{e.author}</span>
            <span className="col-span-2 text-[11px] tabular-nums opacity-70" style={{ fontVariantNumeric: 'oldstyle-nums' }}>{e.year}</span>
            <span className="col-span-1 text-[11px] uppercase tracking-widest text-right opacity-70">{e.categoryCode}</span>
          </li>
        ))}
      </ol>
    </div>
  );
}

export interface Project { id: string; name: string; status: 'green' | 'yellow' | 'red'; weight: number; metric: { label: string; value: number; format: 'count' | 'ms' | 'percent' }; }

// packing.ts — greedy bin packing for tile sizes
export interface Placement { projectId: string; col: number; row: number; w: number; h: number; }

export function pack(projects: ReadonlyArray<Project>, viewportCols: number, density: 'comfortable' | 'compact'): { placements: Placement[]; rows: number } {
  const grid: boolean[][] = [];
  const fits = (row: number, col: number, w: number, h: number) => {
    for (let r = row; r < row + h; r++) {
      while (!grid[r]) grid.push(new Array(viewportCols).fill(false));
      for (let c = col; c < col + w; c++) {
        if (c >= viewportCols) return false;
        if (grid[r][c]) return false;
      }
    }
    return true;
  };
  const mark = (row: number, col: number, w: number, h: number, v: boolean) => {
    for (let r = row; r < row + h; r++) for (let c = col; c < col + w; c++) grid[r][c] = v;
  };
  const sorted = [...projects].sort((a, b) => b.weight - a.weight);
  const placements: Placement[] = [];
  for (const p of sorted) {
    let w = 1, h = 1;
    if (density === 'comfortable') {
      if (p.weight > 0.66) { w = 2; h = 2; }
      else if (p.weight > 0.33) { w = 2; h = 1; }
    }
    let placed = false;
    outer: for (let r = 0; r < 200 && !placed; r++) {
      for (let c = 0; c <= viewportCols - w; c++) {
        if (fits(r, c, w, h)) { mark(r, c, w, h, true); placements.push({ projectId: p.id, col: c, row: r, w, h }); placed = true; break outer; }
      }
    }
  }
  const rows = grid.length;
  return { placements, rows };
}

// Dashboard.tsx
import { useMemo, useState } from 'react';
import type { Project } from './types';
import { pack } from './packing';

interface Props<P extends Project> { projects: ReadonlyArray<P>; onOpen: (id: string) => void; }

export function Dashboard<P extends Project>({ projects, onOpen }: Props<P>) {
  const [density, setDensity] = useState<'comfortable' | 'compact' | 'list'>('comfortable');
  const viewportCols = density === 'comfortable' ? 4 : density === 'compact' ? 6 : 1;
  const { placements } = useMemo(() => pack(projects, viewportCols, density === 'list' ? 'compact' : density), [projects, viewportCols, density]);
  return (
    <div>
      <header className="flex items-center justify-between mb-4">
        <h2 className="text-[16px] font-medium">Projects ({projects.length})</h2>
        <DensityToggle value={density} onChange={setDensity} />
      </header>
      {density === 'list' ? (
        <ul className="divide-y divide-[oklch(0.93_0.005_250)]">
          {projects.map(p => <ListRow key={p.id} project={p} onClick={() => onOpen(p.id)} />)}
        </ul>
      ) : (
        <div className="grid gap-3" style={{ gridTemplateColumns: `repeat(${viewportCols}, minmax(0, 1fr))`, gridAutoRows: density === 'compact' ? '120px' : '160px' }}>
          {placements.map(pl => {
            const p = projects.find(pr => pr.id === pl.projectId);
            if (!p) return null;
            return <Tile key={pl.projectId} project={p} colSpan={pl.w} rowSpan={pl.h} density={density} onClick={() => onOpen(p.id)} />;
          })}
        </div>
      )}
    </div>
  );
}

function DensityToggle({ value, onChange }: { value: 'comfortable' | 'compact' | 'list'; onChange: (v: 'comfortable' | 'compact' | 'list') => void }) {
  const opts: Array<{ v: typeof value; label: string }> = [{ v: 'comfortable', label: '\u2630' }, { v: 'compact', label: '\u2592' }, { v: 'list', label: '\u2261' }];
  return (
    <div role="radiogroup" aria-label="Display density" className="flex border border-[oklch(0.9_0.005_250)] rounded">
      {opts.map(o => (
        <button key={o.v} role="radio" aria-checked={value === o.v} onClick={() => onChange(o.v)}
          className={`px-3 py-1.5 text-[12px] ${value === o.v ? 'bg-[oklch(0.94_0.01_250)] text-[oklch(0.2_0.01_250)]' : 'text-[oklch(0.55_0.005_250)]'}`}>
          {o.label}
        </button>
      ))}
    </div>
  );
}

function Tile({ project, colSpan, rowSpan, density, onClick }: { project: Project; colSpan: number; rowSpan: number; density: 'comfortable' | 'compact'; onClick: () => void }) {
  const STATUS_COLOR = { green: 'oklch(0.6 0.14 145)', yellow: 'oklch(0.75 0.16 80)', red: 'oklch(0.6 0.18 25)' } as const;
  return (
    <button type="button" onClick={onClick} className="text-left bg-[oklch(0.99_0.005_250)] border border-[oklch(0.92_0.005_250)] rounded-md p-4 hover:bg-[oklch(0.97_0.005_250)] transition-[background] duration-[80ms] focus-visible:outline focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-[oklch(0.55_0.18_250)] relative" style={{ gridColumn: `span ${colSpan}`, gridRow: `span ${rowSpan}`, padding: density === 'compact' ? 8 : 16 }}>
      <span aria-hidden="true" className="absolute top-0 left-0 right-0 h-[2px] rounded-t-md" style={{ background: STATUS_COLOR[project.status] }} />
      <div className="flex items-baseline justify-between">
        <span className="text-[14px] font-medium truncate">{project.name}</span>
      </div>
      <div className="mt-3">
        <div className="text-[11px] uppercase tracking-wider text-[oklch(0.55_0.005_250)]">{project.metric.label}</div>
        <div className="text-[22px] tabular-nums font-medium mt-0.5">{formatMetric(project.metric)}</div>
      </div>
