}

function ListRow({ project, onClick }: { project: Project; onClick: () => void }) {
  const STATUS_COLOR = { green: 'oklch(0.6 0.14 145)', yellow: 'oklch(0.75 0.16 80)', red: 'oklch(0.6 0.18 25)' } as const;
  return (
    <li role="listitem"><button type="button" onClick={onClick} className="w-full flex items-center h-14 px-4 text-left hover:bg-[oklch(0.96_0.005_250)] gap-3">
      <span className="w-1 h-6 rounded" style={{ background: STATUS_COLOR[project.status] }} aria-hidden="true" />
      <span className="text-[14px] flex-1 truncate">{project.name}</span>
      <span className="text-[12px] text-[oklch(0.55_0.005_250)]">{project.metric.label}</span>
      <span className="text-[14px] tabular-nums font-medium w-20 text-right">{formatMetric(project.metric)}</span>
    </button></li>
  );
}

function formatMetric(m: Project['metric']): string {
  if (m.format === 'count') return m.value.toLocaleString();
  if (m.format === 'ms') return `${m.value} ms`;
  return `${m.value}%`;
}

export type CellValue = string | number | boolean | null;
export interface Range { startRow: number; startCol: number; endRow: number; endCol: number; }
export type Mode = 'normal' | 'edit' | 'formula' | 'extend';

// SpreadsheetState.tsx
import { createContext, useContext, useReducer } from 'react';
import type { CellValue, Range, Mode } from './types';

interface State { rows: number; cols: number; cells: Map<string, CellValue>; focus: { row: number; col: number }; mode: Mode; editBuffer: string; ranges: Range[]; anchor: { row: number; col: number } | null; }
type Action = { type: 'focus'; row: number; col: number } | { type: 'enterEdit'; initialChar?: string } | { type: 'commit'; nextDir?: 'down' | 'right' | 'up' | 'left' } | { type: 'cancel' } | { type: 'updateBuffer'; value: string } | { type: 'extendTo'; row: number; col: number } | { type: 'addRange'; range: Range };

function key(r: number, c: number) { return `${r}:${c}`; }
function reducer(s: State, a: Action): State {
  switch (a.type) {
    case 'focus': return { ...s, focus: { row: a.row, col: a.col }, mode: 'normal', editBuffer: '', anchor: { row: a.row, col: a.col }, ranges: [] };
    case 'enterEdit': {
      const existing = String(s.cells.get(key(s.focus.row, s.focus.col)) ?? '');
      const buffer = a.initialChar != null ? a.initialChar : existing;
      return { ...s, mode: buffer.startsWith('=') ? 'formula' : 'edit', editBuffer: buffer };
    }
    case 'updateBuffer': return { ...s, editBuffer: a.value, mode: a.value.startsWith('=') ? 'formula' : 'edit' };
    case 'commit': {
      const cells = new Map(s.cells);
      const parsed = parseValue(s.editBuffer);
      cells.set(key(s.focus.row, s.focus.col), parsed);
      let { row, col } = s.focus;
      if (a.nextDir === 'down') row = Math.min(s.rows - 1, row + 1);
      else if (a.nextDir === 'right') col = Math.min(s.cols - 1, col + 1);
      else if (a.nextDir === 'up') row = Math.max(0, row - 1);
      else if (a.nextDir === 'left') col = Math.max(0, col - 1);
      return { ...s, cells, focus: { row, col }, mode: 'normal', editBuffer: '', anchor: { row, col }, ranges: [] };
    }
    case 'cancel': return { ...s, mode: 'normal', editBuffer: '' };
    case 'extendTo': {
      if (!s.anchor) return s;
      const range: Range = { startRow: Math.min(s.anchor.row, a.row), startCol: Math.min(s.anchor.col, a.col), endRow: Math.max(s.anchor.row, a.row), endCol: Math.max(s.anchor.col, a.col) };
      return { ...s, focus: { row: a.row, col: a.col }, ranges: [range], mode: 'extend' };
    }
    case 'addRange': return { ...s, ranges: [...s.ranges, a.range] };
  }
}

function parseValue(s: string): CellValue {
  if (s === '') return null;
  const n = Number(s);
  if (!isNaN(n) && /^-?\d+(\.\d+)?$/.test(s)) return n;
  return s;
}

const Ctx = createContext<{ state: State; dispatch: React.Dispatch<Action> } | null>(null);
export function SpreadsheetProvider({ rows, cols, children }: { rows: number; cols: number; children: React.ReactNode }) {
  const [state, dispatch] = useReducer(reducer, { rows, cols, cells: new Map(), focus: { row: 0, col: 0 }, mode: 'normal', editBuffer: '', ranges: [], anchor: { row: 0, col: 0 } });
  return <Ctx.Provider value={{ state, dispatch }}>{children}</Ctx.Provider>;
}
export function useSpreadsheet() { const v = useContext(Ctx); if (!v) throw new Error('provider'); return v; }

// Spreadsheet.tsx
import { useCallback, useEffect, useRef } from 'react';
import { SpreadsheetProvider, useSpreadsheet } from './SpreadsheetState';

const FORMULA_FUNCTIONS = ['SUM', 'AVERAGE', 'COUNT', 'IF', 'VLOOKUP', 'INDEX', 'MATCH'] as const;

export function Spreadsheet({ rows, cols }: { rows: number; cols: number }) {
  return <SpreadsheetProvider rows={rows} cols={cols}><Inner /></SpreadsheetProvider>;
}

function Inner() {
  const { state, dispatch } = useSpreadsheet();
  const rootRef = useRef<HTMLDivElement | null>(null);
  const inEdit = state.mode === 'edit' || state.mode === 'formula';

  const onKey = useCallback((e: React.KeyboardEvent) => {
    if (state.mode === 'normal') {
      if (e.key === 'ArrowDown') { e.preventDefault(); dispatch({ type: 'focus', row: Math.min(state.rows - 1, state.focus.row + 1), col: state.focus.col }); }
      else if (e.key === 'ArrowUp') { e.preventDefault(); dispatch({ type: 'focus', row: Math.max(0, state.focus.row - 1), col: state.focus.col }); }
      else if (e.key === 'ArrowRight') { e.preventDefault(); dispatch({ type: 'focus', row: state.focus.row, col: Math.min(state.cols - 1, state.focus.col + 1) }); }
      else if (e.key === 'ArrowLeft') { e.preventDefault(); dispatch({ type: 'focus', row: state.focus.row, col: Math.max(0, state.focus.col - 1) }); }
      else if (e.key === 'F2' || e.key === 'Enter') { e.preventDefault(); dispatch({ type: 'enterEdit' }); }
      else if (e.key.length === 1 && !e.metaKey && !e.ctrlKey) { e.preventDefault(); dispatch({ type: 'enterEdit', initialChar: e.key }); }
      if (e.shiftKey && e.key.startsWith('Arrow')) {
        e.preventDefault();
        const dr = e.key === 'ArrowDown' ? 1 : e.key === 'ArrowUp' ? -1 : 0;
        const dc = e.key === 'ArrowRight' ? 1 : e.key === 'ArrowLeft' ? -1 : 0;
        dispatch({ type: 'extendTo', row: state.focus.row + dr, col: state.focus.col + dc });
      }
    } else if (inEdit) {
      if (e.key === 'Escape') { e.preventDefault(); dispatch({ type: 'cancel' }); }
      else if (e.key === 'Enter') { e.preventDefault(); dispatch({ type: 'commit', nextDir: 'down' }); }
      else if (e.key === 'Tab') { e.preventDefault(); dispatch({ type: 'commit', nextDir: e.shiftKey ? 'left' : 'right' }); }
      else if (e.key.startsWith('Arrow')) {
        e.preventDefault();
        const dir = e.key === 'ArrowDown' ? 'down' : e.key === 'ArrowUp' ? 'up' : e.key === 'ArrowRight' ? 'right' : 'left';
        dispatch({ type: 'commit', nextDir: dir });
      }
    }
  }, [state, inEdit, dispatch]);

  return (
    <div ref={rootRef} tabIndex={0} onKeyDown={onKey} className="outline-none inline-block bg-white" aria-label="Spreadsheet" role="grid">
      {Array.from({ length: state.rows }).map((_, r) => (
        <div key={r} role="row" className="flex">
          {Array.from({ length: state.cols }).map((_, c) => {
            const isFocus = state.focus.row === r && state.focus.col === c;
            const inRange = state.ranges.some(rg => r >= rg.startRow && r <= rg.endRow && c >= rg.startCol && c <= rg.endCol);
            const v = state.cells.get(`${r}:${c}`);
            return (
              <div key={c} role="gridcell" aria-selected={isFocus} onClick={() => dispatch({ type: 'focus', row: r, col: c })}
