// useViewportTracker.ts
import { useEffect, useRef } from 'react';
export function useViewportTracker(itemHeight: number, broadcast: (range: [number, number]) => void) {
  const containerRef = useRef<HTMLDivElement | null>(null);
  const timer = useRef<number | null>(null);
  useEffect(() => {
    const el = containerRef.current;
    if (!el) return;
    const compute = () => {
      const start = Math.floor(el.scrollTop / itemHeight);
      const end = Math.ceil((el.scrollTop + el.clientHeight) / itemHeight);
      broadcast([start, end]);
    };
    const onScroll = () => {
      if (timer.current) window.clearTimeout(timer.current);
      timer.current = window.setTimeout(compute, 200);
    };
    compute();
    el.addEventListener('scroll', onScroll, { passive: true });
    return () => { el.removeEventListener('scroll', onScroll); if (timer.current) window.clearTimeout(timer.current); };
  }, [itemHeight, broadcast]);
  return containerRef;
}

// CollaborativeList.tsx
import { useMemo } from 'react';
import { usePresence, colorFor } from './PresenceContext';
import { useViewportTracker } from './useViewportTracker';

interface Item { id: string; title: string; }
interface Props { items: ReadonlyArray<Item>; broadcastViewport: (range: [number, number]) => void; broadcastSelection: (idx: number | null) => void; selectedIdx: number | null; onSelect: (idx: number) => void; }

export function CollaborativeList({ items, broadcastViewport, broadcastSelection, selectedIdx, onSelect }: Props) {
  const { users, localUserId } = usePresence();
  const ITEM_H = 40;
  const containerRef = useViewportTracker(ITEM_H, broadcastViewport);
  const now = Date.now();
  const others = users.filter(u => u.userId !== localUserId);

  const viewportMap = useMemo(() => {
    const m = new Map<number, UserPresence[]>();
    for (const u of others) {
      if (!u.viewportRange) continue;
      const idleFactor = now - u.lastMovedAt > 60000 ? 0.5 : 1;
      if (idleFactor === 0) continue;
      for (let i = u.viewportRange[0]; i < u.viewportRange[1]; i++) {
        if (!m.has(i)) m.set(i, []);
        m.get(i)!.push(u);
      }
    }
    return m;
  }, [others, now]);

  const selectionMap = useMemo(() => {
    const m = new Map<number, UserPresence[]>();
    for (const u of others) {
      if (u.selectedItemIdx == null) continue;
      if (!m.has(u.selectedItemIdx)) m.set(u.selectedItemIdx, []);
      m.get(u.selectedItemIdx)!.push(u);
    }
    return m;
  }, [others]);

  return (
    <div className="flex">
      <div ref={containerRef} className="flex-1 h-[640px] overflow-y-auto bg-white">
        {items.map((item, i) => {
          const viewers = viewportMap.get(i) ?? [];
          const selectors = selectionMap.get(i) ?? [];
          const isLocalSelected = selectedIdx === i;
          return (
            <div key={item.id} role="button" tabIndex={0}
              onClick={() => { onSelect(i); broadcastSelection(i); }}
              className="relative flex items-center h-10 px-3 border-b border-[oklch(0.95_0.005_250)] hover:bg-[oklch(0.97_0.005_250)] cursor-pointer"
              style={{ outline: isLocalSelected ? '2px solid oklch(0.55 0.18 250)' : selectors.length > 0 ? `2px solid ${colorFor(selectors[0].colorIndex).replace(')', ' / 0.6)')}` : 'none', outlineOffset: -2 }}>
              <span className="text-[13px] flex-1 truncate">{item.title}</span>
              {selectors.length > 0 && (
                <div className="flex -space-x-1 mr-2">
                  {selectors.slice(0, 3).map(u => (
                    <span key={u.userId} title={u.userName} className="w-5 h-5 rounded-full border-2 border-white" style={{ background: colorFor(u.colorIndex) }} />
                  ))}
                </div>
              )}
              {viewers.length > 0 && (
                <span aria-hidden="true" className="absolute right-0 top-0 bottom-0 w-[2px]" style={{ background: colorFor(viewers[0].colorIndex).replace(')', ' / 0.4)') }} />
              )}
            </div>
          );
        })}
      </div>
      <PresenceRail others={others} itemCount={items.length} itemHeight={ITEM_H} containerHeight={640} onJump={(i) => { const el = containerRef.current; if (el) el.scrollTop = i * ITEM_H - 200; }} />
    </div>
  );
}

function PresenceRail({ others, itemCount, itemHeight, containerHeight, onJump }: { others: ReadonlyArray<UserPresence>; itemCount: number; itemHeight: number; containerHeight: number; onJump: (i: number) => void }) {
  return (
    <div className="w-8 bg-[oklch(0.97_0.005_250)] relative" style={{ height: containerHeight }} aria-label="Collaborator positions">
      {others.filter(u => u.selectedItemIdx != null).map(u => {
        const ratio = (u.selectedItemIdx as number) / Math.max(itemCount - 1, 1);
        const top = ratio * (containerHeight - 20);
        return (
          <button key={u.userId} type="button" onClick={() => onJump(u.selectedItemIdx as number)}
            aria-label={`Jump to ${u.userName}`}
            className="absolute left-1.5 w-5 h-5 rounded-full border-2 border-white shadow"
            style={{ background: colorFor(u.colorIndex), top, transition: 'top 200ms ease-out' }}
            title={u.userName} />
        );
      })}
    </div>
  );
}

