import { useState, useRef, useCallback, useEffect } from 'react';
export function useToggleConfirmation(value: boolean, onCommit: (v: boolean) => void, importance: 'high' | 'normal') {
  const [optimistic, setOptimistic] = useState(value);
  const [pendingUndo, setPendingUndo] = useState<{ target: boolean; expiresAt: number } | null>(null);
  const timer = useRef<number | null>(null);

  useEffect(() => setOptimistic(value), [value]);

  const set = useCallback((target: boolean) => {
    setOptimistic(target);
    if (importance === 'high') {
      const expiresAt = Date.now() + 8000;
      setPendingUndo({ target, expiresAt });
      if (timer.current) window.clearTimeout(timer.current);
      timer.current = window.setTimeout(() => { onCommit(target); setPendingUndo(null); }, 8000);
    } else {
      onCommit(target);
    }
  }, [importance, onCommit]);

  const undo = useCallback(() => {
    if (timer.current) window.clearTimeout(timer.current);
    setOptimistic(value);
    setPendingUndo(null);
  }, [value]);

  useEffect(() => () => { if (timer.current) window.clearTimeout(timer.current); }, []);
  return { optimistic, pendingUndo, set, undo };
}

