// TimeSeriesChart.tsx
import { useMemo, useRef, useState } from 'react';
import type { Series, ChartEvent } from './types';
import { useTimeDomain } from './useTimeDomain';

interface Props { series: ReadonlyArray<Series>; events: ReadonlyArray<ChartEvent>; fullRange: [number, number]; }

const COLORS = ['oklch(0.6 0.18 250)','oklch(0.65 0.16 145)','oklch(0.65 0.18 25)','oklch(0.7 0.15 60)','oklch(0.62 0.19 300)','oklch(0.6 0.18 200)'];

export function TimeSeriesChart({ series, events, fullRange }: Props) {
  const { domain, setDomain, reset } = useTimeDomain(fullRange);
  const [hoverT, setHoverT] = useState<number | null>(null);
  const [hiddenIds, setHiddenIds] = useState<Set<string>>(new Set());
  const chartRef = useRef<HTMLDivElement | null>(null);

  const W = 720, H_MAIN = 280, H_EVENT = 24, H_CONTEXT = 32;
  const PAD_LEFT = 48;

  const xScale = (t: number) => PAD_LEFT + ((t - domain[0]) / (domain[1] - domain[0])) * (W - PAD_LEFT);
  const xScaleFull = (t: number) => PAD_LEFT + ((t - fullRange[0]) / (fullRange[1] - fullRange[0])) * (W - PAD_LEFT);

  const yExtent = useMemo(() => {
    let lo = Infinity, hi = -Infinity;
    for (const s of series) {
      if (hiddenIds.has(s.id)) continue;
      for (const p of s.points) {
        if (p.t >= domain[0] && p.t <= domain[1]) { if (p.v < lo) lo = p.v; if (p.v > hi) hi = p.v; }
      }
    }
    if (!isFinite(lo)) { lo = 0; hi = 1; }
    return [lo, hi];
  }, [series, hiddenIds, domain]);

  const yScale = (v: number) => H_MAIN - ((v - yExtent[0]) / (yExtent[1] - yExtent[0] || 1)) * (H_MAIN - 16) - 8;

  const seriesPath = (s: Series) => s.points.filter(p => p.t >= domain[0] && p.t <= domain[1]).map((p, i) => `${i ? 'L' : 'M'}${xScale(p.t).toFixed(1)} ${yScale(p.v).toFixed(1)}`).join(' ');

  // Event clustering for overlap
  const eventClusters = useMemo(() => {
    const inView = events.filter(e => e.t >= domain[0] && e.t <= domain[1]).sort((a, b) => a.t - b.t);
    const clusters: Array<{ events: ChartEvent[]; x: number }> = [];
    const THRESHOLD = 12;
    for (const e of inView) {
      const x = xScale(e.t);
      const last = clusters[clusters.length - 1];
      if (last && Math.abs(last.x - x) < THRESHOLD) last.events.push(e);
      else clusters.push({ events: [e], x });
    }
    return clusters;
  }, [events, domain]);

  const EVENT_COLOR: Record<ChartEvent['kind'], string> = { deploy: 'oklch(0.6 0.18 250)', alert: 'oklch(0.6 0.18 25)', config: 'oklch(0.75 0.16 80)' };

  return (
    <div ref={chartRef} className="select-none" style={{ width: W }}>
      <svg width={W} height={H_EVENT}>
        {eventClusters.map((c, i) => (
          <g key={i}>
            <rect x={c.x - 1} y={0} width={c.events.length > 1 ? 4 : 2} height={H_EVENT} fill={EVENT_COLOR[c.events[0].kind]} fillOpacity={0.8} />
            {c.events.length > 1 && <text x={c.x + 5} y={H_EVENT - 6} fontSize="10" fill="oklch(0.4 0.005 250)">+{c.events.length - 1}</text>}
          </g>
        ))}
      </svg>
      <div className="relative" style={{ height: H_MAIN }}
           onMouseMove={(e) => { const rect = e.currentTarget.getBoundingClientRect(); const x = e.clientX - rect.left; const t = domain[0] + ((x - PAD_LEFT) / (W - PAD_LEFT)) * (domain[1] - domain[0]); setHoverT(t); }}
           onMouseLeave={() => setHoverT(null)}>
        <svg width={W} height={H_MAIN} className="absolute inset-0">
          {[0.25, 0.5, 0.75].map(g => <line key={g} x1={PAD_LEFT} y1={H_MAIN * g} x2={W} y2={H_MAIN * g} stroke="oklch(0.95 0.005 250)" strokeWidth="1" />)}
          {series.map((s, i) => {
            const hidden = hiddenIds.has(s.id);
            return <path key={s.id} d={seriesPath(s)} stroke={COLORS[i % COLORS.length]} strokeWidth="1.5" fill="none" style={{ opacity: hidden ? 0 : 1, transition: 'opacity 250ms cubic-bezier(0.22, 1, 0.36, 1)' }} />;
          })}
          {hoverT != null && <line x1={xScale(hoverT)} y1={0} x2={xScale(hoverT)} y2={H_MAIN} stroke="oklch(0.5 0.005 250 / 0.6)" strokeWidth="1" strokeDasharray="2 2" />}
        </svg>
        <div className="absolute top-2 right-2 text-[12px] tabular-nums bg-white/90 backdrop-blur rounded shadow px-2 py-1 flex flex-col gap-0.5">
          {series.map((s, i) => {
            const point = hoverT != null ? s.points.reduce((nearest, p) => Math.abs(p.t - hoverT) < Math.abs(nearest.t - hoverT) ? p : nearest, s.points[0]) : null;
            return (
              <button key={s.id} type="button" onClick={() => setHiddenIds(h => { const n = new Set(h); if (n.has(s.id)) n.delete(s.id); else n.add(s.id); return n; })}
                className={`flex items-center gap-2 text-left ${hiddenIds.has(s.id) ? 'opacity-30' : ''}`}>
                <span className="w-2 h-2 rounded" style={{ background: COLORS[i % COLORS.length] }} />
                <span className="flex-1">{s.label}</span>
                <span>{point ? point.v.toFixed(2) : '—'}</span>
              </button>
            );
          })}
        </div>
      </div>
      <ContextStrip series={series} fullRange={fullRange} domain={domain} setDomain={setDomain} width={W} padLeft={PAD_LEFT} />
    </div>
  );
}

function ContextStrip({ series, fullRange, domain, setDomain, width, padLeft }: { series: ReadonlyArray<Series>; fullRange: [number, number]; domain: [number, number]; setDomain: (d: [number, number]) => void; width: number; padLeft: number }) {
  const H = 32;
  const x = (t: number) => padLeft + ((t - fullRange[0]) / (fullRange[1] - fullRange[0])) * (width - padLeft);
  const dragging = useRef<{ startT: number } | null>(null);
  const onDown = (e: React.MouseEvent<SVGElement>) => {
    const rect = e.currentTarget.getBoundingClientRect();
    const t = fullRange[0] + ((e.clientX - rect.left - padLeft) / (width - padLeft)) * (fullRange[1] - fullRange[0]);
    dragging.current = { startT: t };
  };
  const onMove = (e: React.MouseEvent<SVGElement>) => {
    if (!dragging.current) return;
    const rect = e.currentTarget.getBoundingClientRect();
    const t = fullRange[0] + ((e.clientX - rect.left - padLeft) / (width - padLeft)) * (fullRange[1] - fullRange[0]);
    setDomain([Math.min(dragging.current.startT, t), Math.max(dragging.current.startT, t)]);
  };
  const onUp = () => { dragging.current = null; };
  return (
    <svg width={width} height={H} onMouseDown={onDown} onMouseMove={onMove} onMouseUp={onUp} onMouseLeave={onUp} className="cursor-ew-resize">
      <rect x={padLeft} y={0} width={width - padLeft} height={H} fill="oklch(0.97 0.005 250)" />
      {series.slice(0, 1).map((s, i) => (
        <path key={s.id} d={s.points.map((p, j) => `${j ? 'L' : 'M'}${x(p.t).toFixed(1)} ${(H - (p.v / Math.max(...s.points.map(pp => pp.v), 1)) * H).toFixed(1)}`).join(' ')} stroke="oklch(0.55 0.005 250)" strokeWidth="1" fill="none" />
      ))}
      <rect x={x(domain[0])} y={0} width={x(domain[1]) - x(domain[0])} height={H} fill="oklch(0.55 0.18 250 / 0.15)" stroke="oklch(0.55 0.18 250)" strokeWidth="1" />
    </svg>
  );
}
