    <svg width="16" height="16" viewBox="0 0 16 16" shapeRendering="crispEdges" style={{ imageRendering: 'pixelated' }} aria-hidden="true">
      {/* triangle pointing right, built from 1x1 pixels */}
      <rect x="5" y="3" width="1" height="10" fill="black" />
      <rect x="6" y="4" width="1" height="8" fill="black" />
      <rect x="7" y="5" width="1" height="6" fill="black" />
      <rect x="8" y="6" width="1" height="4" fill="black" />
      <rect x="9" y="7" width="1" height="2" fill="black" />
    </svg>
  );
}

export function PixelPauseIcon() {
  return (
    <svg width="16" height="16" viewBox="0 0 16 16" shapeRendering="crispEdges" aria-hidden="true">
      <rect x="5" y="4" width="2" height="8" fill="black" />
      <rect x="9" y="4" width="2" height="8" fill="black" />
    </svg>
  );
}

// MediaPlayer.tsx
import { useState } from 'react';
import { PixelPlayIcon, PixelPauseIcon } from './PixelIcon';

export function MediaPlayer({ track }: { track: { title: string; artist: string; durationMs: number; positionMs: number } }) {
  const [playing, setPlaying] = useState(false);
  const display = `${track.artist} - ${track.title}`;
  return (
    <div className="y2k-chrome inline-block" style={{ width: 280 }}>
      <div className="y2k-title-bar flex justify-between items-center">
        <span>Player v1.0</span>
        <div className="flex gap-0.5">
          {['_','\u25A1','\u2715'].map(c => <button key={c} type="button" className="y2k-button w-4 h-4 text-[10px] flex items-center justify-center" aria-label={c === '_' ? 'Minimize' : c === '\u25A1' ? 'Maximize' : 'Close'}>{c}</button>)}
        </div>
      </div>
      <div className="p-1.5">
        <div className="y2k-lcd">
          <div className="truncate">{display}</div>
          <div className="flex justify-between mt-0.5">
            <span>{fmt(track.positionMs)}</span>
            <span>-{fmt(track.durationMs - track.positionMs)}</span>
          </div>
        </div>
        <div className="flex gap-0.5 mt-1.5">
          <button type="button" className="y2k-button w-7 h-5" aria-label="Previous"><svg width="16" height="16" viewBox="0 0 16 16" shapeRendering="crispEdges"><rect x="4" y="4" width="1" height="8" fill="black" /><rect x="6" y="8" width="6" height="1" fill="black" /></svg></button>
          <button type="button" className="y2k-button w-7 h-5" onClick={() => setPlaying(p => !p)} aria-label={playing ? 'Pause' : 'Play'}>{playing ? <PixelPauseIcon /> : <PixelPlayIcon />}</button>
          <button type="button" className="y2k-button w-7 h-5" aria-label="Stop"><svg width="16" height="16" viewBox="0 0 16 16" shapeRendering="crispEdges"><rect x="4" y="4" width="8" height="8" fill="black" /></svg></button>
          <button type="button" className="y2k-button w-7 h-5" aria-label="Next"><svg width="16" height="16" viewBox="0 0 16 16" shapeRendering="crispEdges"><rect x="11" y="4" width="1" height="8" fill="black" /><rect x="4" y="8" width="6" height="1" fill="black" /></svg></button>
        </div>
      </div>
    </div>
  );
}

function fmt(ms: number): string {
  const totalSec = Math.floor(ms / 1000);
  const m = Math.floor(totalSec / 60);
  const s = totalSec % 60;
  return `${m}:${String(s).padStart(2, '0')}`;
}
